# # # # # # # # # # # # # # # # # # # # # # # # # #     #     # f_spatial_raw = e_3d_dec.squeeze(1)          # [B,T,1,1] ŌåÆ [B,T]  (squeeze C v├Ā H,W)
# # # # # # # # # # # # # # # # # # # # # # # # # #     #     # f_spatial_raw = f_spatial_raw.mean(dim=1)    # [B] ŌĆö hoß║Ęc giß╗» T nß║┐u muß╗æn
# # # # # # # # # # # # # # # # # # # # # # # # # #     #     # Hoß║Ęc ─æŲĪn giß║Żn hŲĪn: mean chß╗ē spatial
