# # # # # # # # # # # # # # # # # # # # # # # PH├éN T├ŹCH Tß║ĀI SAO FM THUA LSTM:
# # # # # # # # # # # # # # # # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

# # # # # # # # # # # # # # # # # # # # # # # 1. LSTM d├╣ng pure MSE ŌåÆ gradient r├Ą r├Āng, 1 hŲ░ß╗øng duy nhß║źt
# # # # # # # # # # # # # # # # # # # # # # # 2. FM v32 d├╣ng 5+ loss ŌåÆ gradient conflict, model kh├┤ng biß║┐t optimize g├¼
# # # # # # # # # # # # # # # # # # # # # # # 3. SR head ri├¬ng + FM ri├¬ng ŌåÆ discontinuity tß║Īi step 4ŌåÆ5
# # # # # # # # # # # # # # # # # # # # # # # 4. AFCRPS pull ensemble diversity ŌēĀ accuracy ŌåÆ ADE cao

