# # # # # # # # # # # # # # # # # # # # # # # GIß║óI PH├üP V33: 
# # # # # # # # # # # # # # # # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

# # # # # # # # # # # # # # # # # # # # # # # CORE INSIGHT: FM architecture + MSE training = best of both worlds
# # # # # # # # # # # # # # # # # # # # # # #   - FM cho ensemble/uncertainty estimation khi inference
# # # # # # # # # # # # # # # # # # # # # # #   - MSE cho gradient r├Ą r├Āng khi training (nhŲ░ LSTM)
# # # # # # # # # # # # # # # # # # # # # # #   - KH├öNG d├╣ng SR head ri├¬ng ŌåÆ FM predict ALL 12 steps
# # # # # # # # # # # # # # # # # # # # # # #   - KH├öNG d├╣ng AFCRPS khi training ŌåÆ chß╗ē MSE haversine

# # # # # # # # # # # # # # # # # # # # # # # ARCHITECTURE CHANGES:
# # # # # # # # # # # # # # # # # # # # # # #   1. Bß╗Ä ShortRangeHead ŌåÆ FM predict tß║źt cß║Ż 12 steps trß╗▒c tiß║┐p
# # # # # # # # # # # # # # # # # # # # # # #   2. Bß╗Ä sr_anchor_emb ŌåÆ ─æŲĪn giß║Żn h├│a decode
# # # # # # # # # # # # # # # # # # # # # # #   3. TH├ŖM teacher forcing: train FM vß╗øi gt trajectory l├Ām guidance
# # # # # # # # # # # # # # # # # # # # # # #   4. Loss = MSE_haversine + nhß║╣ velocity + nhß║╣ heading (tß╗Ģng 3 loss)

# # # # # # # # # # # # # # # # # # # # # # # TRAINING STRATEGY:
# # # # # # # # # # # # # # # # # # # # # # #   Phase 1 (epoch 0-20): MSE-only, sigma_min lß╗øn (0.1) ŌåÆ near-deterministic
# # # # # # # # # # # # # # # # # # # # # # #     ŌåÆ FM hoß║Īt ─æß╗Öng gß║¦n nhŲ░ regression network
# # # # # # # # # # # # # # # # # # # # # # #     ŌåÆ ADE giß║Żm nhanh tß╗½ 400 ŌåÆ ~200km
    
# # # # # # # # # # # # # # # # # # # # # # #   Phase 2 (epoch 20-50): MSE + nhß║╣ velocity/heading, sigma_min giß║Żm dß║¦n
# # # # # # # # # # # # # # # # # # # # # # #     ŌåÆ Refine trajectory shape
# # # # # # # # # # # # # # # # # # # # # # #     ŌåÆ ADE ~170km, 12h ~45km
    
# # # # # # # # # # # # # # # # # # # # # # #   Phase 3 (epoch 50+): Giß╗» nguy├¬n, fine-tune
# # # # # # # # # # # # # # # # # # # # # # #     ŌåÆ 12h < 50km, 72h < 300km

# # # # # # # # # # # # # # # # # # # # # # # KEY INSIGHT Vß╗Ć FM V├Ć 12h:
# # # # # # # # # # # # # # # # # # # # # # #   - FM C├ō THß╗é ─æß║Īt 12h < 50km Nß║ŠU train ─æ├║ng c├Īch
# # # # # # # # # # # # # # # # # # # # # # #   - Vß║źn ─æß╗ü c┼®: SR head ri├¬ng ŌåÆ FM kh├┤ng ─æŲ░ß╗Żc train cho step 1-4
# # # # # # # # # # # # # # # # # # # # # # #   - V33: FM predict ALL steps ŌåÆ step 1-4 c┼®ng ─æŲ░ß╗Żc optimize trß╗▒c tiß║┐p
# # # # # # # # # # # # # # # # # # # # # # #   - Step weighting nhß║źn mß║Īnh 12h (step 2) v├Ā 24h (step 4)

# # # # # # # # # # # # # # # # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
