# # # # # # # # # # # # # # # # # # # # # # # #  MSE Haversine Loss ŌĆö V┼® kh├Ł ch├Łnh, giß╗æng LSTM nhŲ░ng physically correct
# # # # # # # # # # # # # # # # # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

# # # # # # # # # # # # # # # # # # # # # # # def mse_hav_loss(pred_norm, gt_norm, step_w=None):
# # # # # # # # # # # # # # # # # # # # # # #     """
# # # # # # # # # # # # # # # # # # # # # # #     Haversine MSE per-step.
    
# # # # # # # # # # # # # # # # # # # # # # #     Tß║Īi sao d├╣ng haversine thay v├¼ MSE(lon,lat)?
# # # # # # # # # # # # # # # # # # # # # # #     - MSE(lon,lat) bß╗ŗ bias do cos(lat): 1 degree lon ß╗¤ equator ŌēĀ 1 degree ß╗¤ 30┬░N
# # # # # # # # # # # # # # # # # # # # # # #     - Haversine cho distance thß║Łt sß╗▒ tr├¬n Earth ŌåÆ gradient ch├Łnh x├Īc hŲĪn
# # # # # # # # # # # # # # # # # # # # # # #     - LSTM d├╣ng MSE(lon,lat) ŌåÆ c├│ thß╗ā beat bß║▒ng MSE(haversine)
# # # # # # # # # # # # # # # # # # # # # # #     """
# # # # # # # # # # # # # # # # # # # # # # #     if step_w is None:
# # # # # # # # # # # # # # # # # # # # # # #         step_w = MSE_STEP_WEIGHTS
# # # # # # # # # # # # # # # # # # # # # # #     T = min(pred_norm.shape[0], gt_norm.shape[0])
# # # # # # # # # # # # # # # # # # # # # # #     pred_deg = _norm_to_deg(pred_norm[:T])
# # # # # # # # # # # # # # # # # # # # # # #     gt_deg   = _norm_to_deg(gt_norm[:T])
# # # # # # # # # # # # # # # # # # # # # # #     dist_km  = _haversine_deg(pred_deg, gt_deg)   # [T, B] in km
    
# # # # # # # # # # # # # # # # # # # # # # #     w = pred_norm.new_tensor(step_w[:T])
# # # # # # # # # # # # # # # # # # # # # # #     w = w / w.sum() * T  # normalize nhŲ░ng giß╗» scale
    
# # # # # # # # # # # # # # # # # # # # # # #     # Huber-style: d├╣ng L1 cho outlier (dist > 300km), L2 cho phß║¦n c├▓n lß║Īi
# # # # # # # # # # # # # # # # # # # # # # #     # Tr├Īnh gradient explosion tß╗½ large errors
# # # # # # # # # # # # # # # # # # # # # # #     delta = 300.0  # km
# # # # # # # # # # # # # # # # # # # # # # #     huber_dist = torch.where(
# # # # # # # # # # # # # # # # # # # # # # #         dist_km < delta,
# # # # # # # # # # # # # # # # # # # # # # #         dist_km.pow(2) / (2.0 * delta),
# # # # # # # # # # # # # # # # # # # # # # #         dist_km - delta / 2.0,
# # # # # # # # # # # # # # # # # # # # # # #     )
    
# # # # # # # # # # # # # # # # # # # # # # #     return (huber_dist * w.unsqueeze(1)).mean() / delta


# # # # # # # # # # # # # # # # # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
# # # # # # # # # # # # # # # # # # # # # # # #  VelocityField ŌĆö ─ÉŲĪn giß║Żn h├│a, bß╗Å ShortRangeHead
# # # # # # # # # # # # # # # # # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

