# # # # # # # # # # # # # # # # # # # # # # # class TCFlowMatching(nn.Module):
# # # # # # # # # # # # # # # # # # # # # # #     """
# # # # # # # # # # # # # # # # # # # # # # #     v33: Pure FM architecture, MSE-only training.
    
# # # # # # # # # # # # # # # # # # # # # # #     KEY DIFFERENCES tß╗½ v32:
# # # # # # # # # # # # # # # # # # # # # # #     1. FM predict ALL 12 steps (kh├┤ng c├│ SR head ri├¬ng)
# # # # # # # # # # # # # # # # # # # # # # #     2. Training loss = MSE_haversine + nhß║╣ velocity + nhß║╣ heading
# # # # # # # # # # # # # # # # # # # # # # #     3. KH├öNG d├╣ng AFCRPS ŌåÆ gradient kh├┤ng conflict
# # # # # # # # # # # # # # # # # # # # # # #     4. sigma_min schedule: lß╗øn ban ─æß║¦u (near-deterministic) ŌåÆ nhß╗Å dß║¦n
# # # # # # # # # # # # # # # # # # # # # # #     5. Teacher forcing: d├╣ng gt trajectory interpolation khi train
    
# # # # # # # # # # # # # # # # # # # # # # #     Tß║ĀI SAO FM C├ō THß╗é BEAT LSTM:
# # # # # # # # # # # # # # # # # # # # # # #     - FM c├│ th├¬m encoder mß║Īnh (FNO3D + Mamba + Env_net)
# # # # # # # # # # # # # # # # # # # # # # #     - FM c├│ ensemble capability ŌåÆ uncertainty estimation
# # # # # # # # # # # # # # # # # # # # # # #     - FM c├│ physics correction (beta-drift)
# # # # # # # # # # # # # # # # # # # # # # #     - Nß║┐u train ─æ├║ng (MSE-only), FM ├Łt nhß║źt = LSTM, c├│ thß╗ā tß╗æt hŲĪn
# # # # # # # # # # # # # # # # # # # # # # #     """

# # # # # # # # # # # # # # # # # # # # # # #     def __init__(self, pred_len=12, obs_len=8, sigma_min=0.02,
