# # # # # # # # # # # # # # # # # #                 lat_rad     = torch.deg2rad(pred_deg[:-1, :, 1])
# # # # # # # # # # # # # # # # # #                 cos_lat     = torch.cos(lat_rad).clamp(min=1e-4)
# # # # # # # # # # # # # # # # # #                 speed       = torch.sqrt(
# # # # # # # # # # # # # # # # # #                     (dt_deg[:, :, 0] * cos_lat * 111.0).pow(2)
# # # # # # # # # # # # # # # # # #                     + (dt_deg[:, :, 1] * 111.0).pow(2))
# # # # # # # # # # # # # # # # # #                 loss = F.relu(speed - 600.0).pow(2).mean()
# # # # # # # # # # # # # # # # # #                 loss.backward()
# # # # # # # # # # # # # # # # # #                 torch.nn.utils.clip_grad_norm_([x], 0.05)
# # # # # # # # # # # # # # # # # #                 opt.step()
# # # # # # # # # # # # # # # # # #         return x.detach()

