# # # # # # # # # # # # # # # # #                 t = aug[idx].clone()
# # # # # # # # # # # # # # # # #                 t[..., 0] = -t[..., 0]
# # # # # # # # # # # # # # # # #                 aug[idx] = t
# # # # # # # # # # # # # # # # #         return aug

# # # # # # # # # # # # # # # # #     @staticmethod
# # # # # # # # # # # # # # # # #     def _obs_noise_aug(batch_list, sigma=0.005):
# # # # # # # # # # # # # # # # #         if torch.rand(1).item() > 0.5:
# # # # # # # # # # # # # # # # #             return batch_list
# # # # # # # # # # # # # # # # #         aug = list(batch_list)
# # # # # # # # # # # # # # # # #         if torch.is_tensor(aug[0]):
# # # # # # # # # # # # # # # # #             aug[0] = aug[0] + torch.randn_like(aug[0]) * sigma
