# # # # # # # # # # # # # # # # #         dy_km    = dt_deg[:, :, 1] * 111.0
# # # # # # # # # # # # # # # # #         speed_kmh = torch.sqrt(dx_km**2 + dy_km**2)
# # # # # # # # # # # # # # # # #         speed_penalty = F.relu(speed_kmh - 70.0) + F.relu(10.0 - speed_kmh)
# # # # # # # # # # # # # # # # #         speed_score   = torch.exp(-speed_penalty.mean(0) / 20.0)
