# # # # # # # # # # # # # # # #                         "lon_std_deg":  f"{all_lon[:,k,b].std():.4f}",
# # # # # # # # # # # # # # # #                         "lat_std_deg":  f"{all_lat[:,k,b].std():.4f}",
