# # # # # # # # # # # #     def get_loss_breakdown(self, batch_list, step_weight_alpha=0.0, epoch=0):
# # # # # # # # # # # #         """
# # # # # # # # # # # #         v46: ST-Trans inspired loss ŌĆö Cß╗░C ─ÉŲĀN GIß║óN
        
# # # # # # # # # # # #         Flow:
# # # # # # # # # # # #           1. Augment (flip + noise only)
# # # # # # # # # # # #           2. Encode context
# # # # # # # # # # # #           3. FM forward ŌåÆ predict trajectory
# # # # # # # # # # # #           4. Convert to degrees
# # # # # # # # # # # #           5. ST-Trans loss: DPE + 0.05*MSE + 0.1*speed_penalty + 0.01*accel_penalty
# # # # # # # # # # # #         """
# # # # # # # # # # # #         # ŌöĆŌöĆ Augmentation ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # # # # # #         batch_list = self._lon_flip_aug(batch_list)
# # # # # # # # # # # #         batch_list = self._obs_noise_aug(batch_list, sigma=0.005)

# # # # # # # # # # # #         obs_t    = batch_list[0]
# # # # # # # # # # # #         env_data = batch_list[13] if len(batch_list) > 13 else None
# # # # # # # # # # # #         lp, lm   = obs_t[-1], batch_list[7][-1]

# # # # # # # # # # # #         # ŌöĆŌöĆ Sigma schedule (ST-Trans style) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # # # # # #         # Epoch 0-10: sigma=0.15 (near-deterministic) ŌåÆ fast convergence
# # # # # # # # # # # #         # Epoch 10-40: linear decay ŌåÆ 0.03
# # # # # # # # # # # #         # Epoch 40+: sigma=0.03 (full diversity)
# # # # # # # # # # # #         if epoch < 10:
# # # # # # # # # # # #             current_sigma = 0.15
# # # # # # # # # # # #         elif epoch < 40:
# # # # # # # # # # # #             t = (epoch - 10) / 30.0
# # # # # # # # # # # #             current_sigma = 0.15 - t * (0.15 - 0.03)
# # # # # # # # # # # #         else:
# # # # # # # # # # # #             current_sigma = 0.03

# # # # # # # # # # # #         # ŌöĆŌöĆ Context encoding ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # # # # # #         raw_ctx = self.net._context(batch_list)

# # # # # # # # # # # #         obs_t    = batch_list[0]
# # # # # # # # # # # #         env_data = batch_list[13] if len(batch_list) > 13 else None
# # # # # # # # # # # #         lp, lm   = obs_t[-1], batch_list[7][-1]

# # # # # # # # # # # #         # ŌöĆŌöĆ FM forward ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # # # # # #         x1_rel = self._to_rel(batch_list[1], batch_list[8], lp, lm)
# # # # # # # # # # # #         x_t, fm_t, u_target = self._cfm_noisy(x1_rel, sigma_min=current_sigma)

# # # # # # # # # # # #         pred_vel = self.net.forward_with_ctx(
# # # # # # # # # # # #             x_t, fm_t, raw_ctx, env_data=env_data,
# # # # # # # # # # # #             vel_obs_feat=self.net._get_vel_obs_feat(obs_t),
# # # # # # # # # # # #             steering_feat=self.net._get_steering_feat(env_data, obs_t.shape[1], obs_t.device)
# # # # # # # # # # # #         )

# # # # # # # # # # # #         # ŌöĆŌöĆ FM velocity loss (gradient flows through pred_vel) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # # # # # #         l_fm_mse = F.mse_loss(pred_vel, u_target)

# # # # # # # # # # # #         # ŌöĆŌöĆ Convert to degree coordinates ŌĆö Vß╗ÜI GRADIENT ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # # # # # #         # Bug c┼®: wrap torch.no_grad() ŌåÆ position loss kh├┤ng c├│ gradient!
# # # # # # # # # # # #         # Fix: t├Łnh pred_abs trß╗▒c tiß║┐p tß╗½ pred_vel (c├│ gradient)
# # # # # # # # # # # #         #
# # # # # # # # # # # #         # FM interpolation: x1_pred = x_t + (1 - fm_te) * pred_vel
# # # # # # # # # # # #         # ─É├óy l├Ā ODE 1-step approximation tß║Īi t=fm_t ŌåÆ x1
# # # # # # # # # # # #         # Khi fm_t ~ Uniform(0,1), E[x1_pred] Ōēł x1_gt nß║┐u model tß╗æt
# # # # # # # # # # # #         fm_te   = fm_t.view(x1_rel.shape[0], 1, 1)
# # # # # # # # # # # #         x1_pred = x_t + (1.0 - fm_te) * pred_vel   # [B, T, 4] ŌĆö C├ō GRADIENT
# # # # # # # # # # # #         pred_abs, _ = self._to_abs(x1_pred, lp, lm) # [T, B, 2] normalized

# # # # # # # # # # # #         pred_deg = _norm_to_deg(pred_abs)            # [T, B, 2] degrees ŌĆö C├ō GRADIENT
# # # # # # # # # # # #         gt_deg   = _norm_to_deg(batch_list[1])       # [T, B, 2] degrees

# # # # # # # # # # # #         # ŌöĆŌöĆ ST-Trans loss ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # # # # # #         loss_dict = compute_st_trans_loss(pred_deg, gt_deg, epoch=epoch)

# # # # # # # # # # # #         # Combine: FM velocity loss + ST-Trans position loss
# # # # # # # # # # # #         # Tß╗ē lß╗ć 1:2 ŌĆö position loss l├Ā primary signal
# # # # # # # # # # # #         total = 1.0 * l_fm_mse + 2.0 * loss_dict["total"]

# # # # # # # # # # # #         if torch.isnan(total) or torch.isinf(total):
# # # # # # # # # # # #             total = x_t.new_zeros(())

# # # # # # # # # # # #         # Return dict cho logging
# # # # # # # # # # # #         d = dict(loss_dict)
# # # # # # # # # # # #         d["total"]   = total
# # # # # # # # # # # #         d["fm_mse"]  = l_fm_mse.item()
# # # # # # # # # # # #         d["sigma"]   = current_sigma
