# # # # # # # # # # def compute_speed_stats_from_norm(obs_traj: torch.Tensor) -> dict:
# # # # # # # # # #     """
# # # # # # # # # #     T├Łnh speed statistics tß╗½ normalized obs trajectory.

# # # # # # # # # #     Args:
# # # # # # # # # #         obs_traj: [T_obs, B, 2] ŌĆö normalized (lon_norm, lat_norm)
# # # # # # # # # #                   C├┤ng thß╗®c: lon_deg = (lon_norm * 50 + 1800) / 10
# # # # # # # # # #                              lat_deg = lat_norm * 50 / 10

# # # # # # # # # #     Returns:
# # # # # # # # # #         dict:
# # # # # # # # # #             mean_kmh   ŌĆö tß╗æc ─æß╗Ö trung b├¼nh trong batch
# # # # # # # # # #             std_kmh    ŌĆö std dev
# # # # # # # # # #             p50_kmh    ŌĆö median
# # # # # # # # # #             p75_kmh    ŌĆö 75th percentile
# # # # # # # # # #             p95_kmh    ŌĆö 95th percentile
# # # # # # # # # #             v_opt      ŌĆö target tß╗æc ─æß╗Ö cho soft penalty (= p50)
# # # # # # # # # #             v_sigma    ŌĆö bandwidth Gaussian penalty (= std + 5)
# # # # # # # # # #             v_hard_cap ŌĆö hard upper cap (= p95 * 1.8, clamp 25ŌĆō60)

# # # # # # # # # #     V├Ł dß╗ź kß║┐t quß║Ż tß╗½ sample data trong dataset (6h step):
# # # # # # # # # #         meanŌēł11 km/h, stdŌēł3, p95Ōēł16 km/h
# # # # # # # # # #         ŌåÆ v_opt=11, v_sigma=8, v_hard_cap=29
# # # # # # # # # #     """
# # # # # # # # # #     T = obs_traj.shape[0]
# # # # # # # # # #     if T < 2:
# # # # # # # # # #         return dict(_SPEED_PRIOR)

# # # # # # # # # #     with torch.no_grad():
# # # # # # # # # #         # Convert normalized ŌåÆ degrees
# # # # # # # # # #         lon_deg = (obs_traj[..., 0] * 50.0 + 1800.0) / 10.0   # [T, B]
# # # # # # # # # #         lat_deg = (obs_traj[..., 1] * 50.0) / 10.0             # [T, B]

# # # # # # # # # #         # Step displacements
# # # # # # # # # #         dlon = lon_deg[1:] - lon_deg[:-1]   # [T-1, B]
# # # # # # # # # #         dlat = lat_deg[1:] - lat_deg[:-1]   # [T-1, B]

# # # # # # # # # #         lat_mid = (lat_deg[:-1] + lat_deg[1:]) * 0.5
# # # # # # # # # #         cos_lat = torch.cos(torch.deg2rad(lat_mid)).clamp(min=1e-4)

# # # # # # # # # #         dx_km     = dlon * cos_lat * DEG2KM          # [T-1, B]
# # # # # # # # # #         dy_km     = dlat * DEG2KM
# # # # # # # # # #         speed_kmh = torch.sqrt(dx_km**2 + dy_km**2 + 1e-6) / DT_HOURS

# # # # # # # # # #         speed_flat = speed_kmh.flatten()
# # # # # # # # # #         n          = speed_flat.numel()

# # # # # # # # # #         if n < 4:
# # # # # # # # # #             return dict(_SPEED_PRIOR)

# # # # # # # # # #         mean_s = float(speed_flat.mean())
# # # # # # # # # #         std_s  = float(speed_flat.std().clamp(min=1.0))

# # # # # # # # # #         # Quantiles
# # # # # # # # # #         q = torch.quantile(speed_flat,
# # # # # # # # # #                            torch.tensor([0.50, 0.75, 0.95], device=speed_flat.device))
# # # # # # # # # #         p50 = float(q[0])
# # # # # # # # # #         p75 = float(q[1])
# # # # # # # # # #         p95 = float(q[2])

# # # # # # # # # #         # Adaptive thresholds
# # # # # # # # # #         v_opt      = max(p50, 5.0)                         # Ōēź 5 km/h
# # # # # # # # # #         v_sigma    = max(std_s + 5.0, 5.0)                 # bandwidth
# # # # # # # # # #         v_hard_cap = float(torch.tensor(p95 * 1.8).clamp(25.0, 80.0))

# # # # # # # # # #     return {
# # # # # # # # # #         "mean_kmh"  : mean_s,
# # # # # # # # # #         "std_kmh"   : std_s,
# # # # # # # # # #         "p50_kmh"   : p50,
# # # # # # # # # #         "p75_kmh"   : p75,
# # # # # # # # # #         "p95_kmh"   : p95,
# # # # # # # # # #         "v_opt"     : v_opt,
# # # # # # # # # #         "v_sigma"   : v_sigma,
# # # # # # # # # #         "v_hard_cap": v_hard_cap,
# # # # # # # # # #     }


