# # # # # # # # # def compute_st_trans_loss(pred_deg, gt_deg, epoch=0, speed_stats=None):
# # # # # # # # #     """
# # # # # # # # #     v50 loss:
# # # # # # # # #       DPE(v50_weights) + 0.03*MSE + 0.05*speed + 0.01*accel
# # # # # # # # #       + 0.30*vel_reg  [F1]
# # # # # # # # #       + 0.20*sph_ate  [F2]
# # # # # # # # #       + 0.20*endpoint
# # # # # # # # #       + 0.10*heading
# # # # # # # # #     """
# # # # # # # # #     sp         = speed_stats or _SPEED_PRIOR
