# # # # # # # # #         ep_w += ew
# # # # # # # # #     l_endpoint = ep_total / max(ep_w, 1e-6)

# # # # # # # # #     total = (l_dpe + 0.03*l_mse + 0.05*l_speed + 0.01*l_accel
# # # # # # # # #              + 0.10*l_heading + 0.30*l_vel_reg
# # # # # # # # #              + 0.20*l_sph_ate + 0.20*l_endpoint)

# # # # # # # # #     if torch.isnan(total) or torch.isinf(total):
