# # # # # # # # #         heading=_s(l_heading), vel_reg=_s(l_vel_reg),
# # # # # # # # #         ate=_s(ate_d["ate"]), cte=_s(ate_d["cte"]), sph_ate=_s(l_sph_ate),
# # # # # # # # #         endpoint=_s(l_endpoint),
# # # # # # # # #         ate_mean_km=ate_d.get("ate_mean_km", 0.0),
# # # # # # # # #         cte_mean_km=ate_d.get("cte_mean_km", 0.0),
