# # # # # # # # #  [P1-4] Signed ATE loss ŌĆö Mß╗ÜI
# # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

# # # # # # # # def _signed_ate_loss(pred_deg, gt_deg):
# # # # # # # #     """
# # # # # # # #     [P1-4] Direct along-track error penalization.

# # # # # # # #     Penalize projection cß╗¦a error vector l├¬n along-track direction cß╗¦a GT.
# # # # # # # #     Kh├Īc vß╗øi spherical_ate_cte (d├╣ng bearing angle), h├Ām n├Āy d├╣ng
# # # # # # # #     flat-projection tß║Īi tß╗½ng step ŌåÆ gradient trß╗▒c tiß║┐p hŲĪn.

# # # # # # # #     Positive ATE: pred ─æi chß║Łm hŲĪn GT (b├Żo chŲ░a tß╗øi nŲĪi)
# # # # # # # #     Negative ATE: pred ─æi nhanh hŲĪn GT (b├Żo qua khß╗Åi nŲĪi)
# # # # # # # #     Cß║Ż hai ─æß╗üu bß╗ŗ penalize nhŲ░ nhau.

# # # # # # # #     Tß║Īi sao paper ST-Trans kh├┤ng c├│: hß╗Ź d├╣ng best-track only, kh├┤ng c├│
# # # # # # # #     ERA5 context ŌåÆ model ─æŲĪn giß║Żn hŲĪn, kh├┤ng cß║¦n loss n├Āy.
# # # # # # # #     Vß╗øi FM model phß╗®c tß║Īp hŲĪn, loss n├Āy l├Ā lß╗Żi thß║┐ cß║Īnh tranh.
# # # # # # # #     """
# # # # # # # #     T = min(pred_deg.shape[0], gt_deg.shape[0])
# # # # # # # #     if T < 3:
# # # # # # # #         return pred_deg.new_zeros(())

# # # # # # # #     # Along-track direction tß║Īi mß╗Śi step (tß╗½ GT)
# # # # # # # #     gt_dir = gt_deg[1:T] - gt_deg[:T-1]        # [T-1, B, 2]
# # # # # # # #     gt_dir_n = F.normalize(gt_dir, dim=-1, eps=1e-6)

# # # # # # # #     # Error vector tß║Īi mß╗Śi step
# # # # # # # #     err = pred_deg[1:T] - gt_deg[1:T]          # [T-1, B, 2]

# # # # # # # #     # ATE = projection of error onto along-track direction
# # # # # # # #     ate = (err * gt_dir_n).sum(-1)             # [T-1, B] km (approx, flat)

# # # # # # # #     # Convert to km: lat deg * 111 + lon deg * 111 * cos(lat)
# # # # # # # #     cos_lat = torch.cos(torch.deg2rad(gt_deg[1:T, :, 1])).clamp(1e-4)
# # # # # # # #     ate_lon = err[:, :, 0] * cos_lat * DEG2KM
# # # # # # # #     ate_lat = err[:, :, 1] * DEG2KM
# # # # # # # #     gt_dir_lon = gt_dir_n[:, :, 0] * cos_lat
# # # # # # # #     gt_dir_lat = gt_dir_n[:, :, 1]
# # # # # # # #     gt_dir_km_n = F.normalize(
# # # # # # # #         torch.stack([gt_dir_lon, gt_dir_lat], dim=-1), dim=-1, eps=1e-6)
# # # # # # # #     err_km = torch.stack([ate_lon, ate_lat], dim=-1)
# # # # # # # #     ate_km = (err_km * gt_dir_km_n).sum(-1)   # [T-1, B]

# # # # # # # #     w = pred_deg.new_tensor(STEP_WEIGHTS[1:T]); w = w / w.sum()

# # # # # # # #     # Huber loss tr├¬n ATE_km ─æß╗ā robust vß╗øi outlier
# # # # # # # #     # delta=80km: linear khi ATE > 80km ŌåÆ strong gradient cho large errors
# # # # # # # #     ate_loss = F.huber_loss(
# # # # # # # #         ate_km, torch.zeros_like(ate_km),
# # # # # # # #         delta=80.0, reduction="none"
# # # # # # # #     )
# # # # # # # #     return (ate_loss * w.unsqueeze(1)).mean() / 100.0


# # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
# # # # # # # # #  [P1-5] Direct 72h/48h haversine loss ŌĆö scheduled
# # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

# # # # # # # # def _direct_endpoint_loss(pred_deg, gt_deg, epoch=0):
# # # # # # # #     """
# # # # # # # #     [P1-5] Raw haversine tß║Īi 48h (step 7) v├Ā 72h (step 11), kh├┤ng cap.

# # # # # # # #     Endpoint Huber bß╗ŗ cap tß║Īi delta=150km ŌåÆ gradient nhß╗Å khi error lß╗øn.
# # # # # # # #     Direct haversine: loss tuyß║┐n t├Łnh vß╗øi error ŌåÆ gradient mß║Īnh hŲĪn.

# # # # # # # #     Schedule: weight t─āng dß║¦n tß╗½ ep15 ─æß╗ā tr├Īnh shock gradient khi resume.
# # # # # # # #     ep15: weight=0.10, ep17: 0.25, ep20+: 0.50
# # # # # # # #     """
# # # # # # # #     T = min(pred_deg.shape[0], gt_deg.shape[0])
# # # # # # # #     if T < 4:
# # # # # # # #         return pred_deg.new_zeros(())

# # # # # # # #     # Schedule weight: t─āng dß║¦n sau ep15
# # # # # # # #     base_w = min(0.50, max(0.10, 0.10 + (epoch - 15) * 0.08))

# # # # # # # #     total = pred_deg.new_zeros(())
# # # # # # # #     w_sum = 0.0

# # # # # # # #     # 48h (step 7), 60h (step 9), 72h (step 11) ŌĆö heavy weight ß╗¤ 72h
# # # # # # # #     for s, w, target_km in [
# # # # # # # #         (7,  0.3, 200.0),   # 48h
# # # # # # # #         (9,  0.5, 250.0),   # 60h
# # # # # # # #         (11, 1.5, 297.0),   # 72h ŌĆö target < 297km (paper)
# # # # # # # #     ]:
# # # # # # # #         if s >= T:
# # # # # # # #             continue
# # # # # # # #         dist = _haversine_deg(pred_deg[s], gt_deg[s]).mean()
# # # # # # # #         total = total + w * dist / target_km
# # # # # # # #         w_sum += w

# # # # # # # #     return base_w * total / max(w_sum, 1e-6)


# # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
# # # # # # # # #  [P1-8] compute_st_trans_loss ŌĆö v51 rebalanced
# # # # # # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

# # # # # # # # def compute_st_trans_loss(pred_deg, gt_deg, epoch=0, speed_stats=None):
# # # # # # # #     """
# # # # # # # #     v51 loss ŌĆö Phase 1 ATE fix:

# # # # # # # #     THAY ─Éß╗öI SO Vß╗ÜI v50:
# # # # # # # #       DPE      : 1.0 ŌåÆ 0.60  (giß║Żm, nhŲ░ß╗Øng room cho vel_reg + ate losses)
# # # # # # # #       vel_reg  : 0.30 ŌåÆ 0.60 [P1-3] (t─āng 2x, fix gradient imbalance)
# # # # # # # #       sph_ate  : 0.20 ŌåÆ 0.25 [P1-7] (t─āng nhß║╣, ate_weight ─æ├Ż t─āng 3ŌåÆ5)
# # # # # # # #       endpoint : 0.20 ŌåÆ 0.15 (giß║Żm, nhŲ░ß╗Øng cho direct_endpoint)
# # # # # # # #       signed_ate: Mß╗ÜI 0.40   [P1-4] (impact lß╗øn nhß║źt cho ATE)
# # # # # # # #       direct_ep : Mß╗ÜI 0.50 scheduled [P1-5]
# # # # # # # #       MSE      : 0.03 ŌåÆ 0.02 (giß║Żm nhß║╣)
# # # # # # # #       heading  : 0.10 ŌåÆ 0.08 (CTE ─æ├Ż tß╗æt)

# # # # # # # #     Tß╗Ģng effective weight: 0.60+0.02+0.05+0.01+0.08+0.60+0.25+0.15+0.40+0.50 = 2.66
# # # # # # # #     """
# # # # # # # #     sp         = speed_stats or _SPEED_PRIOR
# # # # # # # #     v_opt      = sp.get("v_opt",      15.0)
# # # # # # # #     v_sigma    = sp.get("v_sigma",    10.0)
# # # # # # # #     v_hard_cap = sp.get("v_hard_cap", 35.0)
# # # # # # # #     T = min(pred_deg.shape[0], gt_deg.shape[0])
# # # # # # # #     if T < 2:
# # # # # # # #         return {"total": pred_deg.new_zeros(()), "dpe": 0.0, "vel_reg": 0.0}

# # # # # # # #     # ŌöĆŌöĆ DPE (Huber, v50 weights) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # #     w    = pred_deg.new_tensor(STEP_WEIGHTS[:T]); w = w / w.sum() * T
# # # # # # # #     dist = _haversine_deg(pred_deg[:T], gt_deg[:T])
# # # # # # # #     d    = 200.0
# # # # # # # #     l_dpe = ((torch.where(dist < d,
# # # # # # # #                           dist.pow(2) / (2*d),
# # # # # # # #                           dist - d/2)) * w.unsqueeze(1)).mean() / d

# # # # # # # #     # ŌöĆŌöĆ MSE (stability) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # #     l_mse = F.mse_loss(pred_deg[:T], gt_deg[:T])

# # # # # # # #     # ŌöĆŌöĆ Speed prior ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # #     pred_spd = _step_speeds_deg(pred_deg[:T])
# # # # # # # #     l_speed  = (0.7 * ((pred_spd - v_opt) / v_sigma).pow(2).mean() +
# # # # # # # #                 0.3 * F.relu(pred_spd - v_hard_cap).pow(2).mean() / v_hard_cap**2
# # # # # # # #                 ) if pred_spd.shape[0] > 0 else pred_deg.new_zeros(())

# # # # # # # #     # ŌöĆŌöĆ Accel ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # #     l_accel = (((pred_spd[1:] - pred_spd[:-1]).abs() / DT_HOURS).pow(2).mean()
# # # # # # # #                / max(v_sigma * 0.5, 3.0)**2
# # # # # # # #                ) if pred_spd.shape[0] >= 2 else pred_deg.new_zeros(())

# # # # # # # #     # ŌöĆŌöĆ Heading ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # #     if T >= 3:
# # # # # # # #         pv = pred_deg[1:T] - pred_deg[:T-1]
# # # # # # # #         gv = gt_deg[1:T]   - gt_deg[:T-1]
# # # # # # # #         l_heading = (1.0 - (
# # # # # # # #             F.normalize(pv.reshape(-1, 2), dim=-1, eps=1e-6) *
# # # # # # # #             F.normalize(gv.reshape(-1, 2), dim=-1, eps=1e-6)
# # # # # # # #         ).sum(-1)).mean().clamp(0.0, 2.0)
# # # # # # # #     else:
# # # # # # # #         l_heading = pred_deg.new_zeros(())

# # # # # # # #     # ŌöĆŌöĆ [P1-3] Velocity regression ├Ś 0.60 ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # # # # # # #     l_vel_reg = _velocity_regression_loss(pred_deg, gt_deg, speed_stats)

# # # # # # # #     # ŌöĆŌöĆ [P1-7] Spherical ATE/CTE (ate_weight=5.0) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
