# # # # # # # #     def _cfm_noisy(self, x1, sigma_min=None, lp=None):
# # # # # # # #         """
# # # # # # # #         [P1-2] Linear interpolant (use_slerp=False mß║Ęc ─æß╗ŗnh).

# # # # # # # #         u_target = x1 - x0 (constant, kh├┤ng phß╗ź thuß╗Öc t)
# # # # # # # #         ŌåÆ gradient flow ß╗Ģn ─æß╗ŗnh, fm_mse spikes ─æŲ░ß╗Żc loß║Īi bß╗Å
# # # # # # # #         ŌåÆ fm_mse vß╗ü range 0.3-0.8 thay v├¼ 0.5-2.7
# # # # # # # #         """
# # # # # # # #         if sigma_min is None: sigma_min = self.sigma_min
# # # # # # # #         B = x1.shape[0]; device = x1.device
# # # # # # # #         x0 = torch.randn_like(x1) * sigma_min
# # # # # # # #         t  = torch.rand(B, device=device)
# # # # # # # #         if self.use_slerp and x1.shape[-1] >= 2:
# # # # # # # #             # SLERP path ŌĆö chß╗ē khi user explicitly set use_slerp=True
# # # # # # # #             x_t      = _slerp_interpolant(x0, x1, t, lp=lp)
# # # # # # # #             u_target = _slerp_velocity_target(x0, x1, t, lp=lp)
# # # # # # # #         else:
# # # # # # # #             # [P1-2] Linear ŌĆö default
# # # # # # # #             te       = t.view(B, 1, 1)
# # # # # # # #             x_t      = (1.0 - te)*x0 + te*x1
# # # # # # # #             u_target = x1 - x0          # constant velocity target
