# # # # # # # #     @staticmethod
# # # # # # # #     def _sigma_schedule(epoch):
# # # # # # # #         """
# # # # # # # #         [P1-6] Aggressive sigma schedule.

# # # # # # # #         v50: 0.10ŌåÆ0.04 over ep2-20 (qu├Ī chß║Łm ŌåÆ FM hß╗Źc mean trajectory ŌåÆ ATE cao)
# # # # # # # #         v51: 0.10ŌåÆ0.04 over ep2-10, sau ep10: 0.03

# # # # # # # #         Sigma thß║źp sß╗øm ŌåÆ FM kh├┤ng bß╗ŗ pull vß╗ü mean trajectory ŌåÆ
# # # # # # # #         predict trajectory cß╗ź thß╗ā hŲĪn ŌåÆ ATE giß║Żm trß╗▒c tiß║┐p.
# # # # # # # #         """
# # # # # # # #         if epoch < 2:   return 0.10
# # # # # # # #         if epoch < 10:  return 0.10 - (epoch-2)/8.0 * (0.10 - 0.04)
