# # # # # # # def compute_st_trans_loss(pred_deg, gt_deg, epoch=0, speed_stats=None):
# # # # # # #     """
# # # # # # #     v52 loss ŌĆö Balanced ATE/CTE:

# # # # # # #     THAY ─Éß╗öI SO Vß╗ÜI v51:
# # # # # # #       vel_reg    : bß╗Å ratio, giß╗» abs+vec; clamp min=5.0    [FIX-P1-B]
# # # # # # #       heading    : 0.08 ŌåÆ 0.20 (CTE supervision)          [FIX-P2-C]
