# # # # # # #     L├Į thuyß║┐t:
# # # # # # #       ATE (speed error)     ŌåÆ vel_reg + signed_ate
# # # # # # #       CTE (direction error) ŌåÆ heading + signed_cte + sph_ate(cte_w=2.5)
# # # # # # #       Cß║Ż hai share         ŌåÆ DPE + endpoint + direct_ep

# # # # # # #     Budget (rough):
