# # # # def _signed_ate_loss(pred_deg, gt_deg):
# # # #     """
# # # #     [FIX-P1-A] Direct along-track error penalization.
# # # #     FIX: t├Łnh gt_dir trong km-space tß╗½ ─æß║¦u, tr├Īnh double cos_lat.

# # # #     v51 bug: gt_dir_n = normalize(delta_degrees) ŌåÆ rß╗ōi nh├ón cos_lat
# # # #              ŌåÆ double-counting vß╗øi hŲ░ß╗øng ch├®o NW/SW
# # # #     v52 fix: dx_km = delta_lon * cos_lat * 111
# # # #              dy_km = delta_lat * 111
# # # #              gt_dir_km_n = normalize([dx_km, dy_km])
# # # #     """
# # # #     T = min(pred_deg.shape[0], gt_deg.shape[0])
