# # # # #  [FIX-P2-B] Signed CTE loss ŌĆö mirror cß╗¦a signed_ate
# # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

# # # # def _signed_cte_loss(pred_deg, gt_deg):
# # # #     """
# # # #     [FIX-P2-B] Direct cross-track error penalization.
# # # #     Mirror cß╗¦a _signed_ate_loss nhŲ░ng lß║źy perpendicular direction.
# # # #     Cross-track = projection cß╗¦a error l├¬n hŲ░ß╗øng vu├┤ng g├│c vß╗øi track.

# # # #     Tß║Īi sao cß║¦n: _spherical_ate_cte_loss d├╣ng bearing difference
# # # #                  ŌåÆ indirect gradient cho CTE
# # # #     H├Ām n├Āy: direct projection ŌåÆ mß║Īnh hŲĪn khi error lß╗øn
# # # #     """
# # # #     T = min(pred_deg.shape[0], gt_deg.shape[0])
# # # #     if T < 3:
# # # #         return pred_deg.new_zeros(())

# # # #     cos_lat = torch.cos(torch.deg2rad(gt_deg[1:T, :, 1])).clamp(1e-4)

# # # #     # Along-track direction trong km
# # # #     dx_km = (gt_deg[1:T, :, 0] - gt_deg[:T-1, :, 0]) * cos_lat * DEG2KM
# # # #     dy_km = (gt_deg[1:T, :, 1] - gt_deg[:T-1, :, 1]) * DEG2KM
# # # #     gt_dir_km_n = F.normalize(
# # # #         torch.stack([dx_km, dy_km], dim=-1), dim=-1, eps=1e-6)

# # # #     # Cross-track direction = perpendicular (rotate 90┬░)
# # # #     # n = (-dy, dx) normalized
# # # #     ct_dir_km_n = torch.stack([-gt_dir_km_n[..., 1],
# # # #                                  gt_dir_km_n[..., 0]], dim=-1)  # [T-1, B, 2]

# # # #     # Error vector trong km
# # # #     err_lon_km = (pred_deg[1:T, :, 0] - gt_deg[1:T, :, 0]) * cos_lat * DEG2KM
# # # #     err_lat_km = (pred_deg[1:T, :, 1] - gt_deg[1:T, :, 1]) * DEG2KM
# # # #     err_km = torch.stack([err_lon_km, err_lat_km], dim=-1)

# # # #     # CTE = projection l├¬n cross-track direction
# # # #     cte_km = (err_km * ct_dir_km_n).sum(-1)   # [T-1, B]

# # # #     w = pred_deg.new_tensor(STEP_WEIGHTS[1:T]); w = w / w.sum()

# # # #     cte_loss = F.huber_loss(
# # # #         cte_km, torch.zeros_like(cte_km),
# # # #         delta=80.0, reduction="none"
# # # #     )
# # # #     return (cte_loss * w.unsqueeze(1)).mean() / 100.0


# # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
# # # # #  [FIX-ATE-5] Speed bias loss ŌĆö penalize under-prediction asymmetrically
# # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

# # # # def _speed_bias_loss(pred_deg, gt_deg, speed_stats=None):
# # # #     """
# # # #     [FIX-ATE-5] Penalize systematic speed under-prediction.

# # # #     SCS TCs thŲ░ß╗Øng T─éNG tß╗æc ŌåÆ persistence/model hay under-predict speed
# # # #     ŌåÆ ATE dŲ░ŲĪng (pred ngß║»n hŲĪn gt) l├Ā systematic error

# # # #     Standard vel_reg penalizes |pred_spd - gt_spd|┬▓ symmetrically
# # # #     ŌåÆ Kh├┤ng ─æß╗¦ ─æß╗ā break systematic under-prediction bias

# # # #     This loss: asymmetrically penalizes under-prediction harder:
# # # #       if pred_spd < gt_spd: loss = (gt_spd - pred_spd)┬▓ ├Ś 2.0
# # # #       if pred_spd > gt_spd: loss = (pred_spd - gt_spd)┬▓ ├Ś 0.5
# # # #     """
# # # #     T = min(pred_deg.shape[0], gt_deg.shape[0])
# # # #     if T < 2:
# # # #         return pred_deg.new_zeros(())

# # # #     pred_spd = _step_speeds_deg(pred_deg[:T])   # [T-1, B]
# # # #     gt_spd   = _step_speeds_deg(gt_deg[:T])     # [T-1, B]
# # # #     gt_spd_c = gt_spd.clamp(min=5.0)

# # # #     w = pred_deg.new_tensor(STEP_WEIGHTS[1:T]); w = w / w.sum()

# # # #     # Signed error: positive = under-predict (pred slower than gt)
# # # #     signed_err = gt_spd_c - pred_spd   # positive = under-predict

# # # #     # Asymmetric: punish under-prediction 4├Ś harder than over-prediction
# # # #     under_mask = (signed_err > 0).float()
# # # #     over_mask  = (signed_err <= 0).float()

# # # #     sq_err = signed_err.pow(2)
# # # #     asym_loss = (sq_err * (4.0 * under_mask + 1.0 * over_mask)
# # # #                  * w.unsqueeze(1)).mean()

# # # #     sp = speed_stats or _SPEED_PRIOR
# # # #     v_sigma = sp.get("v_sigma", 10.0)
# # # #     return (asym_loss / max(v_sigma**2, 1.0)).clamp(0.0, 5.0)


# # # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
