# # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
# # # #  [FIX-ATE] compute_st_trans_loss ŌĆö v54 ATE-focused
# # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

# # # def compute_st_trans_loss(pred_deg, gt_deg, epoch=0, speed_stats=None):
# # #     """
# # #     v54 loss ŌĆö ATE breakthrough edition:

# # #     KEY CHANGES vs v53:
# # #       [FIX-ATE-2] signed_ate: 0.40ŌåÆ0.80 (double ATE supervision)
# # #       [FIX-ATE-2] signed_cte: 0.25ŌåÆ0.08 (CTE=54km >> 0.08 sufficient)
# # #       [FIX-ATE-2] heading:    0.20ŌåÆ0.08 (CTE already excellent)
# # #       [FIX-ATE-3] Adaptive epoch schedule: ATE weight increases as CTE converges
# # #       [FIX-ATE-4] vel_reg:    0.60ŌåÆ1.20 (double speed supervision)
# # #       [FIX-ATE-5] speed_bias: NEW asymmetric under-prediction penalty
# # #       [FIX-ATE-5] sph_ate:    ate_w=2.0ŌåÆ3.5, cte_w=2.5ŌåÆ1.0 (rebalance)

# # #     Gradient budget:
# # #       ATE: 1.20(vel) + w_ate(sig_ate) + 0.25(speed_bias) + 3.5/4.5(sph) Ōēł 2.9+
# # #       CTE: 0.08(head) + 0.08(sig_cte) + 1.0/4.5(sph)                    Ōēł 0.38
# # #       Ratio: ~7.6:1 ATE:CTE (CTE already at 54km, ATE needs the focus)
# # #     """
# # #     sp         = speed_stats or _SPEED_PRIOR
# # #     v_opt      = sp.get("v_opt",      15.0)
# # #     v_sigma    = sp.get("v_sigma",    10.0)
# # #     v_hard_cap = sp.get("v_hard_cap", 35.0)
# # #     T = min(pred_deg.shape[0], gt_deg.shape[0])
# # #     if T < 2:
# # #         return {"total": pred_deg.new_zeros(()), "dpe": 0.0, "vel_reg": 0.0}

# # #     # ŌöĆŌöĆ [FIX-ATE-3] Adaptive ATE weight schedule ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     # After ep30 (CTE converged), gradually increase ATE pressure
# # #     # signed_ate weight: 0.80 ŌåÆ up to 1.40 by ep60
# # #     w_signed_ate = min(2.00, 0.80 + max(0, epoch - 30) * 0.04)  # [FIX-v57-G]
# # #     # signed_cte weight: 0.08 ŌåÆ as low as 0.05 at ep60+ (CTE stable)
# # #     w_signed_cte = max(0.05, 0.08 - max(0, epoch - 30) * 0.001)
# # #     # heading weight: 0.08 (fixed, small CTE regularizer)
# # #     w_heading = 0.08

# # #     # ŌöĆŌöĆ DPE (Huber) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     w    = pred_deg.new_tensor(STEP_WEIGHTS[:T]); w = w / w.sum() * T
# # #     dist = _haversine_deg(pred_deg[:T], gt_deg[:T])
# # #     d    = 200.0
# # #     l_dpe = ((torch.where(dist < d,
# # #                           dist.pow(2) / (2*d),
# # #                           dist - d/2)) * w.unsqueeze(1)).mean() / d

# # #     # ŌöĆŌöĆ MSE (stability) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     l_mse = F.mse_loss(pred_deg[:T], gt_deg[:T])

# # #     # ŌöĆŌöĆ Speed prior ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     pred_spd = _step_speeds_deg(pred_deg[:T])
# # #     l_speed  = (0.7 * ((pred_spd - v_opt) / v_sigma).pow(2).mean() +
# # #                 0.3 * F.relu(pred_spd - v_hard_cap).pow(2).mean() / v_hard_cap**2
# # #                 ) if pred_spd.shape[0] > 0 else pred_deg.new_zeros(())

# # #     # ŌöĆŌöĆ Accel ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     l_accel = (((pred_spd[1:] - pred_spd[:-1]).abs() / DT_HOURS).pow(2).mean()
# # #                / max(v_sigma * 0.5, 3.0)**2
# # #                ) if pred_spd.shape[0] >= 2 else pred_deg.new_zeros(())

# # #     # ŌöĆŌöĆ Heading (km-space, CTE regularizer) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     if T >= 3:
# # #         cos_lat_h = torch.cos(torch.deg2rad(
# # #             (gt_deg[:T-1,:,1] + gt_deg[1:T,:,1]) * 0.5)).clamp(1e-4)
# # #         pv_raw = pred_deg[1:T] - pred_deg[:T-1]
# # #         gv_raw = gt_deg[1:T]   - gt_deg[:T-1]
# # #         pv_km = torch.stack([pv_raw[...,0]*cos_lat_h*DEG2KM,
# # #                               pv_raw[...,1]*DEG2KM], dim=-1)
# # #         gv_km = torch.stack([gv_raw[...,0]*cos_lat_h*DEG2KM,
# # #                               gv_raw[...,1]*DEG2KM], dim=-1)
# # #         l_heading = (1.0 - (
# # #             F.normalize(pv_km.reshape(-1, 2), dim=-1, eps=1e-6) *
# # #             F.normalize(gv_km.reshape(-1, 2), dim=-1, eps=1e-6)
# # #         ).sum(-1)).mean().clamp(0.0, 2.0)
# # #     else:
# # #         l_heading = pred_deg.new_zeros(())

# # #     # ŌöĆŌöĆ [FIX-ATE-4] Velocity regression ├Ś 1.20 ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     l_vel_reg = _velocity_regression_loss(pred_deg, gt_deg, speed_stats)

# # #     # ŌöĆŌöĆ [FIX-ATE-5] Speed bias loss (asymmetric under-prediction penalty) ŌöĆŌöĆŌöĆŌöĆ
# # #     l_speed_bias = _speed_bias_loss(pred_deg, gt_deg, speed_stats)

# # #     # ŌöĆŌöĆ Spherical ATE/CTE (ATE-reweighted) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     # [FIX-ATE-5] ate_w: 2.0ŌåÆ3.5, cte_w: 2.5ŌåÆ1.0
# # #     ate_d     = _spherical_ate_cte_loss(pred_deg[:T], gt_deg[:T],
# # #                                         ate_weight=3.5, cte_weight=1.0)
# # #     l_sph_ate = ate_d["ate_cte_total"]

# # #     # ŌöĆŌöĆ Endpoint Huber ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     d2 = 150.0
# # #     ep_total, ep_w = pred_deg.new_zeros(()), 0.0
# # #     for s, ew in [(7, 0.5), (9, 0.8), (10, 1.2), (11, 2.0)]:
# # #         if s >= T:
# # #             continue
# # #         de = _haversine_deg(pred_deg[s], gt_deg[s])
# # #         ep_total = ep_total + ew * torch.where(
# # #             de < d2, de.pow(2) / (2*d2), de - d2/2).mean() / d2
# # #         ep_w += ew
# # #     l_endpoint = ep_total / max(ep_w, 1e-6)

# # #     # ŌöĆŌöĆ Signed ATE (km-space) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     l_signed_ate = _signed_ate_loss(pred_deg, gt_deg)

# # #     # ŌöĆŌöĆ Signed CTE (small regularizer) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     l_signed_cte = _signed_cte_loss(pred_deg, gt_deg)

# # #     # ŌöĆŌöĆ Direct endpoint (scheduled) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     l_direct_ep = _direct_endpoint_loss(pred_deg, gt_deg, epoch=epoch)

# # #     # ŌöĆŌöĆ Total ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
# # #     total = (0.60 * l_dpe
# # #              + 0.02 * l_mse
# # #              + 0.05 * l_speed
# # #              + 0.01 * l_accel
# # #              + w_heading    * l_heading       # [FIX-ATE-2] 0.20ŌåÆ0.08
# # #              + 2.00 * l_vel_reg      # [FIX-v57-F] 1.20ŌåÆ2.00               # [FIX-ATE-4] 0.60ŌåÆ1.20
# # #              + 0.30 * l_speed_bias   # [FIX-v57-F] 0.25ŌåÆ0.30            # [FIX-ATE-5] NEW
# # #              + 0.25 * l_sph_ate               # ATE-reweighted
# # #              + 0.15 * l_endpoint
# # #              + w_signed_ate * l_signed_ate    # [FIX-ATE-2+3] 0.40ŌåÆ0.80~1.40
# # #              + w_signed_cte * l_signed_cte    # [FIX-ATE-2+3] 0.25ŌåÆ0.08~0.05
# # #              + l_direct_ep)                   # scheduled

# # #     if torch.isnan(total) or torch.isinf(total):
# # #         total = pred_deg.new_zeros(())

# # #     def _s(x): return x.item() if torch.is_tensor(x) else float(x)
# # #     return dict(
# # #         total        = total,
# # #         dpe          = _s(l_dpe),
# # #         mse          = _s(l_mse),
# # #         speed        = _s(l_speed),
# # #         accel        = _s(l_accel),
# # #         heading      = _s(l_heading),
# # #         vel_reg      = _s(l_vel_reg),
# # #         speed_bias   = _s(l_speed_bias),
# # #         ate          = _s(ate_d["ate"]),
# # #         cte          = _s(ate_d["cte"]),
# # #         sph_ate      = _s(l_sph_ate),
# # #         endpoint     = _s(l_endpoint),
# # #         signed_ate   = _s(l_signed_ate),
# # #         signed_cte   = _s(l_signed_cte),
# # #         direct_ep    = _s(l_direct_ep),
# # #         w_signed_ate = w_signed_ate,
# # #         w_signed_cte = w_signed_cte,
# # #         ate_mean_km  = ate_d.get("ate_mean_km", 0.0),
# # #         cte_mean_km  = ate_d.get("cte_mean_km", 0.0),
# # #         speed_match=0.0, acc_kmh2=0.0, aux_fno=0.0, sigma=0.0,
# # #         fm_mse=0.0, multi_marg=0.0, rollout_ate=0.0, rollout_w=0.0,
# # #     )


# # # # Alias
# # # compute_ate_focused_loss = compute_st_trans_loss


# # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
# # # #  Sinkhorn OT (giß╗» nguy├¬n tß╗½ v51)
# # # # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

# # # def _sinkhorn_log(cost, epsilon=0.05, n_iter=50):
