STEP_WEIGHTS = [3.0, 2.5, 2.0, 2.0, 2.0, 2.5, 3.0, 4.0, 5.0, 6.0, 7.0, 10.0]

_SPEED_PRIOR = {"v_opt": 15.0, "v_sigma": 10.0, "v_hard_cap": 35.0}

