#  Coordinate utilities  (unchanged from v62)
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

def _norm_to_deg(t: torch.Tensor) -> torch.Tensor:
    """Normalized ŌåÆ geographic degrees."""
    return torch.stack([
        (t[..., 0] * 50.0 + 1800.0) / 10.0,  # lon
        (t[..., 1] * 50.0) / 10.0,            # lat
    ], dim=-1)


def _haversine_deg(p1: torch.Tensor, p2: torch.Tensor) -> torch.Tensor:
    """Haversine distance (km) between geographic coordinates (degrees)."""
    lat1 = torch.deg2rad(p1[..., 1]); lat2 = torch.deg2rad(p2[..., 1])
    dlat = torch.deg2rad(p2[..., 1] - p1[..., 1])
    dlon = torch.deg2rad(p2[..., 0] - p1[..., 0])
    a = (torch.sin(dlat / 2).pow(2) +
         torch.cos(lat1) * torch.cos(lat2) * torch.sin(dlon / 2).pow(2))
    return 2.0 * R_EARTH * torch.asin(a.clamp(1e-12, 1 - 1e-12).sqrt())


def _forward_azimuth(p1: torch.Tensor, p2: torch.Tensor) -> torch.Tensor:
    lon1 = torch.deg2rad(p1[..., 0]); lat1 = torch.deg2rad(p1[..., 1])
    lon2 = torch.deg2rad(p2[..., 0]); lat2 = torch.deg2rad(p2[..., 1])
    dlon = lon2 - lon1
    y = torch.sin(dlon) * torch.cos(lat2)
    x = (torch.cos(lat1) * torch.sin(lat2)
         - torch.sin(lat1) * torch.cos(lat2) * torch.cos(dlon))
    return torch.atan2(y, x)


def _step_speeds_deg(traj_deg: torch.Tensor) -> torch.Tensor:
    if traj_deg.shape[0] < 2:
        return traj_deg.new_zeros(1, traj_deg.shape[1])
    return _haversine_deg(traj_deg[:-1], traj_deg[1:]) / DT_HOURS


def _unwrap_model(m):
    return m._orig_mod if hasattr(m, "_orig_mod") else m


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  Speed statistics  (unchanged from v62)
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

def compute_speed_stats_from_norm(obs_traj: torch.Tensor) -> dict:
    T = obs_traj.shape[0]
    if T < 2:
        return dict(_SPEED_PRIOR)
    with torch.no_grad():
        lon_deg = (obs_traj[..., 0] * 50.0 + 1800.0) / 10.0
        lat_deg = (obs_traj[..., 1] * 50.0) / 10.0
        dlon    = lon_deg[1:] - lon_deg[:-1]
        dlat    = lat_deg[1:] - lat_deg[:-1]
        cos_lat = torch.cos(torch.deg2rad(
            (lat_deg[:-1] + lat_deg[1:]) * 0.5)).clamp(1e-4)
        speed   = torch.sqrt(
            (dlon * cos_lat * DEG2KM)**2 + (dlat * DEG2KM)**2 + 1e-6
        ) / DT_HOURS
        sf = speed.flatten()
        if sf.numel() < 4:
            return dict(_SPEED_PRIOR)
        mean_s = float(sf.mean())
        std_s  = float(sf.std().clamp(min=1.0))
        q      = torch.quantile(sf, torch.tensor([.50, .75, .95], device=sf.device))
        p50, p95 = float(q[0]), float(q[2])
    return {
        "mean_kmh"  : mean_s,  "std_kmh"   : std_s,
        "p50_kmh"   : p50,     "p95_kmh"   : p95,
        "v_opt"     : max(p50, 5.0),
        "v_sigma"   : max(std_s + 5.0, 5.0),
        "v_hard_cap": float(torch.tensor(p95 * 1.8).clamp(25.0, 80.0)),
    }


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  EMA  (unchanged from v62)
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

class EMAModel:
    def __init__(self, model, decay=0.995):
        self.decay  = decay
        m = _unwrap_model(model)
        self.shadow = {k: v.detach().clone()
                       for k, v in m.state_dict().items()
                       if v.dtype.is_floating_point}

    def update(self, model):
        m = _unwrap_model(model)
        with torch.no_grad():
            for k, v in m.state_dict().items():
                if k in self.shadow:
                    self.shadow[k].mul_(self.decay).add_(
                        v.detach(), alpha=1 - self.decay)

    def apply_to(self, model):
        m = _unwrap_model(model)
        backup, sd = {}, m.state_dict()
        for k in self.shadow:
            if k not in sd: continue
            backup[k] = sd[k].detach().clone()
            sd[k].copy_(self.shadow[k])
        return backup

    def restore(self, model, backup):
        m = _unwrap_model(model)
        sd = m.state_dict()
        for k, v in backup.items():
            if k in sd: sd[k].copy_(v)


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  [C1] Intensity-Dependent Steering Extractor  ŌåÉ NEW
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

class IntensitySteeringExtractor(nn.Module):
    """
    [C1] Physics-grounded source distribution component.

    Computes intensity-dependent effective steering displacement per 6-hour step
    in normalized coordinate space.

    Physical basis:
      Weak TC  (TD, TS):   850 hPa steering dominates  ŌåÆ w_low Ōēł 0.6
      Moderate (Cat1-2):   700-500 hPa balanced        ŌåÆ w_mid Ōēł 0.5
      Strong   (Cat3-5):   500-300 hPa deep-layer mean ŌåÆ w_high Ōēł 0.5
      SuperTY:             300-200 hPa upper steering   ŌåÆ w_high Ōēł 0.7

    The model receives one-hot intensity class (6 classes: TDŌåÆSuperTY) and
    produces a learned pressure-level weight vector. This allows the network
    to discover the correct steering level weighting from data.

    Reference for physics prior:
      Lin et al. (2023) ŌĆö physics downscaling, manually tuned per basin
      SHIPS developmental dataset ŌĆö empirical DLM by intensity
      THIS WORK: jointly learned from ERA5 + IBTrACS, novel for ML FM
    """
    N_INTENSITY = 6   # TD, TS, Cat1, Cat2, Cat3, Cat4/5/SuperTY

    def __init__(self, hidden_dim: int = 128, n_levels: int = 3):
        super().__init__()
        self.n_levels = n_levels

        # ŌöĆŌöĆ Intensity ŌåÆ pressure-level attention weights ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        # Input: one-hot intensity class (6-dim)
        # Output: unnormalized weights for [low, mid, high] steering levels
        # Architecture: small MLP with physical prior initialization
        self.intensity_gate = nn.Sequential(
            nn.Linear(self.N_INTENSITY, 64), nn.GELU(), nn.LayerNorm(64),
            nn.Linear(64, n_levels)
        )

        # ŌöĆŌöĆ Wind-field feature extractor per level ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        # Input per level: (u, v) ├Ś n_levels = 6 wind scalars total
        # We also include steering_speed * (cos_dir, sin_dir) as third "level"
        # Total input: u_low, v_low, u_mid, v_mid, u_deep_cos, u_deep_sin = 6
        self.wind_extractor = nn.Sequential(
            nn.Linear(6, hidden_dim), nn.GELU(), nn.LayerNorm(hidden_dim),
            nn.Linear(hidden_dim, hidden_dim // 2), nn.GELU(),
        )

        # ŌöĆŌöĆ Per-level projections: hidden/2 ŌåÆ 2D displacement ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        # Each level has its own projection (physical separation)
        self.level_projs = nn.ModuleList([
            nn.Linear(hidden_dim // 2, 2) for _ in range(n_levels)
        ])

        # ŌöĆŌöĆ Magnitude scale (learnable, initialized to ~realistic values) ŌöĆŌöĆ
        # Physical scale: 10 m/s wind ├Ś 6h ├Ę (5┬░/norm) ├Ę 111 km/┬░ Ōēł 0.097 norm
        self.disp_scale = nn.Parameter(torch.ones(1) * 0.08)

        self._init_weights()

    def _init_weights(self):
        with torch.no_grad():
            # Initialize intensity_gate to encode physical prior:
            #   intensity 0 (TD)  ŌåÆ high weight on low level  ŌåÆ [1, 0, -1]
            #   intensity 5 (STY) ŌåÆ high weight on high level ŌåÆ [-1, 0, 1]
            # Linear interpolation between these extremes
            bias_init = torch.tensor([0.5, 0.0, -0.5])  # prior: low-level default
            self.intensity_gate[-1].bias.data.copy_(bias_init)
            nn.init.xavier_uniform_(self.intensity_gate[-1].weight, gain=0.3)

            # Small initialization for level projections
            for proj in self.level_projs:
                nn.init.xavier_uniform_(proj.weight, gain=0.1)
                nn.init.zeros_(proj.bias)

    def _safe_env(self, env_data: Optional[dict], key: str, norm: float,
                  B: int, device) -> torch.Tensor:
        """Safely extract a scalar field from env_data."""
        if env_data is None:
            return torch.zeros(B, device=device)
        v = env_data.get(key)
        if v is None or not torch.is_tensor(v):
            return torch.zeros(B, device=device)
        v = v.float().to(device)
        while v.dim() > 1:
            v = v.mean(-1)
        if v.numel() < B:
            return torch.zeros(B, device=device)
        return (v.view(-1)[:B] / norm).clamp(-3.0, 3.0)

    def forward(
        self,
        env_data: Optional[dict],
        B: int,
        device,
        intensity_class_onehot: Optional[torch.Tensor] = None,
    ) -> Tuple[torch.Tensor, torch.Tensor]:
        """
        Returns:
            v_steer : (B, 2) effective steering displacement per 6h step (normalized)
            level_w : (B, 3) pressure-level attention weights (sums to 1)
        """
        # ŌöĆŌöĆ Extract steering wind proxies ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        # Level 0 (low ~850hPa proxy): local TC environment wind
        u_low  = self._safe_env(env_data, "u500_center",    30.0, B, device)
        v_low  = self._safe_env(env_data, "v500_center",    30.0, B, device)
        # Level 1 (mid ~500hPa): regional mean flow
        u_mid  = self._safe_env(env_data, "u500_mean",      30.0, B, device)
        v_mid  = self._safe_env(env_data, "v500_mean",      30.0, B, device)
        # Level 2 (high ~DLM proxy): deep-layer mean steering
        spd    = self._safe_env(env_data, "steering_speed", 1.0,  B, device)
        cos_d  = self._safe_env(env_data, "steering_dir_cos", 1.0, B, device)
        sin_d  = self._safe_env(env_data, "steering_dir_sin", 1.0, B, device)
        u_deep = spd * cos_d  # reconstruct 2D vector
        v_deep = spd * sin_d

        # Wind feature vector: (B, 6)
        wind_feat = torch.stack(
            [u_low, v_low, u_mid, v_mid, u_deep, v_deep], dim=-1)

        # Shared wind representation: (B, hidden//2)
        wind_repr = self.wind_extractor(wind_feat)

        # Per-level displacement predictions: each (B, 2)
        level_disps = torch.stack(
            [proj(wind_repr) for proj in self.level_projs], dim=1)  # (B, 3, 2)

        # ŌöĆŌöĆ Intensity-dependent weights ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        if intensity_class_onehot is not None:
            ic = intensity_class_onehot.float().to(device)
            if ic.shape[0] != B:
                ic = torch.zeros(B, self.N_INTENSITY, device=device)
        else:
            ic = torch.zeros(B, self.N_INTENSITY, device=device)

        # Level weights: (B, 3), summing to 1
        raw_w  = self.intensity_gate(ic)            # (B, 3)
        level_w = F.softmax(raw_w, dim=-1)          # (B, 3) Ōłæ=1

        # Weighted combination: (B, 2)
        v_raw = (level_disps * level_w.unsqueeze(-1)).sum(dim=1)

        # Scale to physical displacement magnitude
        v_steer = v_raw * torch.sigmoid(self.disp_scale)

        return v_steer, level_w


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  [C2] Non-Autoregressive Transformer Head  ŌåÉ NEW
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

class NonARTransformerHead(nn.Module):
    """
    [C2] Parallel trajectory decoder ŌĆö no autoregressive error accumulation.

    Architecture:
      ctx (B, ctx_dim) ŌåÆ memory (B, 1, ctx_dim)
      step_queries (1, T, ctx_dim) ŌåÆ expanded (B, T, ctx_dim)
      TransformerDecoder(queries, memory) ŌåÆ (B, T, hidden)
      ŌåÆ cumsum(out_proj(decoded)) + lp ŌåÆ (T, B, 2) positions

    Advantages over GRU ARHead (v62):
      1. ALL T steps attend to FULL context simultaneously
      2. No error accumulation (each step is independent of previous errors)
      3. 100% haversine gradient directly to encoder
      4. Natural long-range temporal dependencies via attention
      5. Parallel decoding ŌåÆ faster inference
      6. Pre-LayerNorm for training stability at deeper layers

    Gradient path:
      haversine(nar_pred, GT) ŌåÆ nar_head ŌåÆ ctx_fc2_nar ŌåÆ raw_ctx ŌåÆ encoder
      ŌåÆ 100% THUß║”N ATE gradient l├¬n encoder (giß╗æng LSTM baseline)
    """

    def __init__(
        self,
        ctx_dim:  int = 256,
        pred_len: int = 12,
        n_heads:  int = 8,
        n_layers: int = 3,
        dropout:  float = 0.10,
        expand_memory: int = 4,   # expand context to multi-token memory
    ):
        super().__init__()
        self.pred_len = pred_len
        self.ctx_dim  = ctx_dim

        # Learned positional queries: one per prediction step
        # Encodes temporal position; trained jointly with decoder
        self.step_queries = nn.Parameter(
            torch.randn(1, pred_len, ctx_dim) * 0.02)

        # Context ŌåÆ multi-token memory (richer conditioning)
        # expand_memory > 1 allows context to attend to multiple memory tokens
        self.ctx_to_mem = nn.Linear(ctx_dim, expand_memory * ctx_dim)
        self.expand_memory = expand_memory

        # Pre-LN Transformer decoder (more stable than post-LN for deep models)
        decoder_layer = nn.TransformerDecoderLayer(
            d_model     = ctx_dim,
            nhead       = n_heads,
            dim_feedforward = ctx_dim * 4,
            dropout     = dropout,
            activation  = "gelu",
            batch_first = True,
            norm_first  = True,   # Pre-LN for stability
        )
        self.transformer = nn.TransformerDecoder(
            decoder_layer, num_layers=n_layers)

        # Output: decoded hidden ŌåÆ per-step (╬ölon, ╬ölat)
        # Using cumulative displacement ensures smooth trajectory
        self.out_proj = nn.Sequential(
            nn.LayerNorm(ctx_dim),
            nn.Linear(ctx_dim, 256), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(256, 2),      # (╬ölon, ╬ölat) in normalized coords
        )

        # Learnable displacement scale (initialized small, learns true scale)
        self.disp_scale = nn.Parameter(torch.ones(1) * 0.3)

        self._init_weights()

    def _init_weights(self):
        with torch.no_grad():
            nn.init.trunc_normal_(self.step_queries, std=0.02)
            for m in self.out_proj.modules():
                if isinstance(m, nn.Linear):
                    nn.init.xavier_uniform_(m.weight, gain=0.3)
                    if m.bias is not None:
                        nn.init.zeros_(m.bias)
            nn.init.xavier_uniform_(self.ctx_to_mem.weight, gain=0.5)
            nn.init.zeros_(self.ctx_to_mem.bias)

    def forward(self, ctx: torch.Tensor, lp: torch.Tensor) -> torch.Tensor:
        """
        Args:
            ctx : (B, ctx_dim) ŌĆö context vector (gradient flows here ŌåÆ encoder)
            lp  : (B, 2)       ŌĆö last observed position in normalized coords

        Returns:
            pred_abs : (T, B, 2) ŌĆö predicted absolute positions (normalized)
        """
        B = ctx.shape[0]

        # Build multi-token memory from context: (B, M, ctx_dim)
        mem_flat = self.ctx_to_mem(ctx)                 # (B, M*ctx_dim)
        memory   = mem_flat.view(B, self.expand_memory, self.ctx_dim)

        # Expand learned step queries to batch: (B, T, ctx_dim)
        queries = self.step_queries.expand(B, -1, -1)

        # Parallel decoding: all T steps simultaneously attend to context
        decoded = self.transformer(queries, memory)      # (B, T, ctx_dim)

        # Project to displacements: (B, T, 2)
        delta = self.out_proj(decoded) * torch.sigmoid(self.disp_scale)

        # Cumulative sum ŌåÆ absolute positions from last observation
        # pos[t] = lp + ╬Ż_{s=0}^{t} delta[s]
        delta_cumsum = delta.cumsum(dim=1)              # (B, T, 2)
        pred_abs     = lp.unsqueeze(1) + delta_cumsum  # (B, T, 2)

        return pred_abs.permute(1, 0, 2)               # (T, B, 2)


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  [C3] Calibration Losses  ŌåÉ NEW
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

def _energy_score_loss(
    ensemble_deg: torch.Tensor,
    gt_deg:       torch.Tensor,
    beta:         float = 1.0,
) -> torch.Tensor:
    """
    [C3] Energy Score ŌĆö proper scoring rule for probabilistic TC track forecasts.

    ES(P, y) = E_P[ŌĆ¢X ŌłÆ yŌĆ¢_hav] ŌłÆ (╬▓/2)┬ĘE_{P├ŚP'}[ŌĆ¢X ŌłÆ X'ŌĆ¢_hav]

    where X, X' ~ P are independent ensemble draws, y = ground truth.

    Mathematical properties (Gneiting & Raftery, 2007):
      - Proper: minimised iff P = true distribution
      - Consistent: encourages both accuracy and diversity
      - ╬▓=1: standard energy score; ╬▓<1: emphasises accuracy more

    Physical interpretation for TC track:
      - First term: ensemble should be close to observed track
      - Second term: ensemble should NOT collapse (diversity rewarded)
      ŌåÆ When TC near bifurcation, spread increases automatically

    Args:
        ensemble_deg : (N, T, B, 2) ŌĆö N ensemble samples in degrees
        gt_deg       : (T, B, 2)    ŌĆö ground truth in degrees
        beta         : diversity weight (0.5ŌĆō1.0, default 1.0)

    Returns: scalar ES loss
    """
    N, T, B, _ = ensemble_deg.shape

    # ŌöĆŌöĆ Term 1: E[ŌĆ¢X ŌłÆ yŌĆ¢] ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    gt_exp     = gt_deg.unsqueeze(0).expand(N, -1, -1, -1)   # (N, T, B, 2)
    dist_to_gt = _haversine_deg(
        ensemble_deg.reshape(N * T * B, 2).unsqueeze(-2),
        gt_exp.reshape(N * T * B, 2).unsqueeze(-2),
    ).reshape(N, T, B)                                        # (N, T, B) km
    term1 = dist_to_gt.mean(0)                                # (T, B)

    # ŌöĆŌöĆ Term 2: (╬▓/2)┬ĘE[ŌĆ¢X ŌłÆ X'ŌĆ¢] ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    # Subsample pairs (O(N┬▓) ŌåÆ O(n_pairs)), efficient for training
    n_pairs = min(max(N * (N - 1) // 2, 4), 20)
    idx     = torch.randint(0, N, (n_pairs, 2), device=ensemble_deg.device)

    s1 = ensemble_deg[idx[:, 0]].reshape(n_pairs * T * B, 2).unsqueeze(-2)
    s2 = ensemble_deg[idx[:, 1]].reshape(n_pairs * T * B, 2).unsqueeze(-2)
    spread = _haversine_deg(s1, s2).reshape(n_pairs, T, B)    # (n_pairs, T, B)
    term2  = spread.mean(0)                                    # (T, B)

    # ŌöĆŌöĆ Step-weighted Energy Score ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    sw  = torch.tensor(STEP_WEIGHTS[:T], device=ensemble_deg.device, dtype=torch.float)
    sw  = sw / sw.sum()
    es  = (term1 - beta * 0.5 * term2) * sw.unsqueeze(1)     # (T, B)
    return es.mean() / 200.0                                   # normalize to ~1


def _spread_error_calibration_loss(
    ensemble_deg: torch.Tensor,
    gt_deg:       torch.Tensor,
) -> torch.Tensor:
    """
    [C3] Spread-Error calibration loss.

    A well-calibrated probabilistic forecast satisfies:
      ensemble_spread Ōēł RMSE(ensemble_mean, observation)
      (reliability diagram should lie on diagonal)

    This loss penalises departure in log-space (handles scale differences):
      L_cal = ╬Ż_t w_t ┬Ę (log(spread_t + 1) ŌłÆ log(error_t + 1))┬▓

    Log-space is important because spread/error can range from ~10 to ~500 km.
    Detach error from computational graph ŌåÆ calibration loss only adjusts spread,
    not the mean prediction (which is handled by other losses).

    Physical meaning:
      Bifurcation scenarios (e.g. TC near subtropical ridge edge):
        ŌåÆ True spread large ŌåÆ model should output large spread
      Straight-track monsoon trough cases:
        ŌåÆ True spread small ŌåÆ model should output small spread
      Without this loss, FM tends to produce constant spread (overconfident or
      overdispersive depending on training regime).

    Args:
        ensemble_deg : (N, T, B, 2) ensemble samples in degrees
        gt_deg       : (T, B, 2)   ground truth in degrees

    Returns: scalar calibration loss
    """
    N, T, B, _ = ensemble_deg.shape

    # ŌöĆŌöĆ Mean prediction ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    mean_deg = ensemble_deg.mean(0)                            # (T, B, 2)

    # ŌöĆŌöĆ Actual error: haversine(mean, gt) [km] ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    error_km = _haversine_deg(mean_deg, gt_deg)               # (T, B)

    # ŌöĆŌöĆ Ensemble spread: per-step haversine std ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    # Approximate spread via position variance in km
    # Use gt lat for cos correction (gt is always valid)
    lat_deg = gt_deg[:, :, 1]                                  # (T, B)
    cos_lat = torch.cos(torch.deg2rad(lat_deg)).clamp(1e-4)    # (T, B)

    # Std of ensemble in normalized coords
    spread_norm = ensemble_deg.std(0)                          # (T, B, 2)
    spread_lon_km = spread_norm[:, :, 0] * cos_lat * DEG2KM * _NORM_TO_DEG
    spread_lat_km = spread_norm[:, :, 1]                       * DEG2KM * _NORM_TO_DEG
    spread_km = torch.sqrt(spread_lon_km.pow(2) + spread_lat_km.pow(2) + 1e-6)

    # ŌöĆŌöĆ Log-space calibration loss ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    log_spread = torch.log(spread_km + 1.0)
    log_error  = torch.log(error_km.detach() + 1.0)  # detach: only tune spread

    sw  = torch.tensor(STEP_WEIGHTS[:T], device=ensemble_deg.device, dtype=torch.float)
    sw  = sw / sw.sum()
    cal = (log_spread - log_error).pow(2) * sw.unsqueeze(1)
    return cal.mean()


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  Existing loss functions  (kept from v62, slightly adapted)
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

def _spherical_ate_cte_loss(pred_deg, gt_deg, ate_weight=3.5, cte_weight=1.0):
    T = min(pred_deg.shape[0], gt_deg.shape[0])
    if T < 2:
        zero = pred_deg.new_zeros(())
        return {"ate": zero, "cte": zero, "ate_cte_total": zero,
                "ate_mean_km": 0.0, "cte_mean_km": 0.0}
    bear_along = _forward_azimuth(gt_deg[:T-1],   gt_deg[1:T])
    bear_error = _forward_azimuth(gt_deg[1:T],    pred_deg[1:T])
    total_err  = _haversine_deg(pred_deg[1:T], gt_deg[1:T])
    angle = bear_error - bear_along
    ate   = total_err * torch.cos(angle)
    cte   = total_err * torch.sin(angle)
    w = pred_deg.new_tensor(STEP_WEIGHTS[1:T])
    w = w / w.sum() * (T - 1)
    ate_t = 200.0; cte_t = 100.0
    ate_loss = (torch.where(ate.abs() < ate_t,
                            ate.pow(2) / (2*ate_t), ate.abs() - ate_t/2)
                * w.unsqueeze(1)).mean() / ate_t
    cte_loss = (torch.where(cte.abs() < cte_t,
                            cte.pow(2) / (2*cte_t), cte.abs() - cte_t/2)
                * w.unsqueeze(1)).mean() / cte_t
    total = ate_weight * ate_loss + cte_weight * cte_loss
    return {"ate": ate_loss, "cte": cte_loss, "ate_cte_total": total,
            "ate_mean_km": float(ate.abs().mean()),
            "cte_mean_km": float(cte.abs().mean())}


def _velocity_regression_loss(pred_deg, gt_deg, speed_stats=None):
    sp      = speed_stats or _SPEED_PRIOR
    v_sigma = sp.get("v_sigma", 10.0)
    T = min(pred_deg.shape[0], gt_deg.shape[0])
    if T < 2:
        return pred_deg.new_zeros(())
    pred_spd = _step_speeds_deg(pred_deg[:T])
    gt_spd   = _step_speeds_deg(gt_deg[:T])
    w = pred_deg.new_tensor(STEP_WEIGHTS[1:T]); w = w / w.sum()
    gt_spd_c = gt_spd.clamp(min=5.0)
    l_abs = ((pred_spd - gt_spd_c).pow(2) / v_sigma**2
             * w.unsqueeze(1)).mean()
    plon = pred_deg[1:T,:,0] - pred_deg[:T-1,:,0]
    plat = pred_deg[1:T,:,1] - pred_deg[:T-1,:,1]
    glon = gt_deg[1:T,:,0]   - gt_deg[:T-1,:,0]
    glat = gt_deg[1:T,:,1]   - gt_deg[:T-1,:,1]
    cos  = torch.cos(torch.deg2rad(
        (pred_deg[:T-1,:,1] + pred_deg[1:T,:,1]) * 0.5)).clamp(1e-4)
    pv_km = torch.stack([plon*cos*DEG2KM/DT_HOURS, plat*DEG2KM/DT_HOURS], -1)
    gv_km = torch.stack([glon*cos*DEG2KM/DT_HOURS, glat*DEG2KM/DT_HOURS], -1)
    l_vec = (F.mse_loss(pv_km, gv_km, reduction="none").mean(-1)
             / v_sigma**2 * w.unsqueeze(1)).mean()
    return (0.5*l_abs + 0.5*l_vec).clamp(0.0, 20.0)


def _signed_ate_loss(pred_deg, gt_deg):
    T = min(pred_deg.shape[0], gt_deg.shape[0])
    if T < 3:
        return pred_deg.new_zeros(())
    cos_lat = torch.cos(torch.deg2rad(gt_deg[1:T, :, 1])).clamp(1e-4)
    dx_km = (gt_deg[1:T,:,0] - gt_deg[:T-1,:,0]) * cos_lat * DEG2KM
    dy_km = (gt_deg[1:T,:,1] - gt_deg[:T-1,:,1]) * DEG2KM
    gt_dir_km_n = F.normalize(torch.stack([dx_km, dy_km], dim=-1), dim=-1, eps=1e-6)
    err_lon_km = (pred_deg[1:T,:,0] - gt_deg[1:T,:,0]) * cos_lat * DEG2KM
    err_lat_km = (pred_deg[1:T,:,1] - gt_deg[1:T,:,1]) * DEG2KM
    err_km = torch.stack([err_lon_km, err_lat_km], dim=-1)
    ate_km = (err_km * gt_dir_km_n).sum(-1)
    w = pred_deg.new_tensor(STEP_WEIGHTS[1:T]); w = w / w.sum()
    return (F.huber_loss(ate_km, torch.zeros_like(ate_km), delta=80.0,
                         reduction="none") * w.unsqueeze(1)).mean() / 100.0


def _signed_cte_loss(pred_deg, gt_deg):
    T = min(pred_deg.shape[0], gt_deg.shape[0])
    if T < 3:
        return pred_deg.new_zeros(())
    cos_lat = torch.cos(torch.deg2rad(gt_deg[1:T, :, 1])).clamp(1e-4)
    dx_km = (gt_deg[1:T,:,0] - gt_deg[:T-1,:,0]) * cos_lat * DEG2KM
    dy_km = (gt_deg[1:T,:,1] - gt_deg[:T-1,:,1]) * DEG2KM
    gt_dir_km_n = F.normalize(torch.stack([dx_km, dy_km], dim=-1), dim=-1, eps=1e-6)
    ct_dir = torch.stack([-gt_dir_km_n[..., 1], gt_dir_km_n[..., 0]], dim=-1)
    err_lon_km = (pred_deg[1:T,:,0] - gt_deg[1:T,:,0]) * cos_lat * DEG2KM
    err_lat_km = (pred_deg[1:T,:,1] - gt_deg[1:T,:,1]) * DEG2KM
    err_km = torch.stack([err_lon_km, err_lat_km], dim=-1)
    cte_km = (err_km * ct_dir).sum(-1)
    w = pred_deg.new_tensor(STEP_WEIGHTS[1:T]); w = w / w.sum()
    return (F.huber_loss(cte_km, torch.zeros_like(cte_km), delta=80.0,
                         reduction="none") * w.unsqueeze(1)).mean() / 100.0


def _speed_bias_loss(pred_deg, gt_deg, speed_stats=None):
    T = min(pred_deg.shape[0], gt_deg.shape[0])
    if T < 2:
        return pred_deg.new_zeros(())
    pred_spd = _step_speeds_deg(pred_deg[:T])
    gt_spd   = _step_speeds_deg(gt_deg[:T]).clamp(min=5.0)
    w = pred_deg.new_tensor(STEP_WEIGHTS[1:T]); w = w / w.sum()
    signed_err = gt_spd - pred_spd
    under = (signed_err > 0).float()
    over  = (signed_err <= 0).float()
    sq_err = signed_err.pow(2)
    asym = (sq_err * (4.0 * under + 1.0 * over) * w.unsqueeze(1)).mean()
    sp = speed_stats or _SPEED_PRIOR
    return (asym / max(sp.get("v_sigma", 10.0)**2, 1.0)).clamp(0.0, 5.0)


def _direct_endpoint_loss(pred_deg, gt_deg, epoch=0):
    T = min(pred_deg.shape[0], gt_deg.shape[0])
    if T < 4:
        return pred_deg.new_zeros(())
    base_w = min(0.50, max(0.10, 0.10 + (epoch - 15) * 0.08))
    total, w_sum = pred_deg.new_zeros(()), 0.0
    for s, w, t_km in [(7, 0.3, 200.0), (9, 0.5, 250.0), (11, 1.5, 297.0)]:
        if s >= T: continue
        d = _haversine_deg(pred_deg[s], gt_deg[s]).mean()
        total = total + w * d / t_km
        w_sum += w
    return base_w * total / max(w_sum, 1e-6)


def compute_ssfm_loss(pred_deg, gt_deg, epoch=0, speed_stats=None):
    """Combined trajectory loss (ATE-focused, adapted from v62)."""
    sp         = speed_stats or _SPEED_PRIOR
    v_opt      = sp.get("v_opt",      15.0)
    v_sigma    = sp.get("v_sigma",    10.0)
    v_hard_cap = sp.get("v_hard_cap", 35.0)
    T = min(pred_deg.shape[0], gt_deg.shape[0])
    if T < 2:
        return {"total": pred_deg.new_zeros(()), "dpe": 0.0, "vel_reg": 0.0}

    w_sat = min(2.00, 0.80 + max(0, epoch - 30) * 0.04)
    w_sct = max(0.05, 0.08 - max(0, epoch - 30) * 0.001)

    w  = pred_deg.new_tensor(STEP_WEIGHTS[:T]); w = w / w.sum() * T
    d  = 200.0
    dist = _haversine_deg(pred_deg[:T], gt_deg[:T])
    l_dpe  = ((torch.where(dist < d, dist.pow(2)/(2*d), dist - d/2))
              * w.unsqueeze(1)).mean() / d
    l_mse  = F.mse_loss(pred_deg[:T], gt_deg[:T])

    pred_spd = _step_speeds_deg(pred_deg[:T])
    l_speed  = (0.7*((pred_spd-v_opt)/v_sigma).pow(2).mean() +
                0.3*F.relu(pred_spd-v_hard_cap).pow(2).mean()/v_hard_cap**2
               ) if pred_spd.shape[0] > 0 else pred_deg.new_zeros(())

    if T >= 3:
        cos_lat_h = torch.cos(torch.deg2rad(
            (gt_deg[:T-1,:,1]+gt_deg[1:T,:,1])*0.5)).clamp(1e-4)
        pv = pred_deg[1:T] - pred_deg[:T-1]
        gv = gt_deg[1:T]   - gt_deg[:T-1]
        pv_km = torch.stack([pv[...,0]*cos_lat_h*DEG2KM, pv[...,1]*DEG2KM], -1)
        gv_km = torch.stack([gv[...,0]*cos_lat_h*DEG2KM, gv[...,1]*DEG2KM], -1)
        l_heading = (1.0 - (F.normalize(pv_km.reshape(-1,2), dim=-1, eps=1e-6) *
                             F.normalize(gv_km.reshape(-1,2), dim=-1, eps=1e-6)
                            ).sum(-1)).mean().clamp(0.0, 2.0)
    else:
        l_heading = pred_deg.new_zeros(())

    l_vel     = _velocity_regression_loss(pred_deg, gt_deg, speed_stats)
    l_sbias   = _speed_bias_loss(pred_deg, gt_deg, speed_stats)
    ate_d     = _spherical_ate_cte_loss(pred_deg[:T], gt_deg[:T],
                                        ate_weight=3.5, cte_weight=1.0)
    d2 = 150.0
    ep_total, ep_w = pred_deg.new_zeros(()), 0.0
    for s, ew in [(7, 0.5), (9, 0.8), (10, 1.2), (11, 2.0)]:
        if s >= T: continue
        de = _haversine_deg(pred_deg[s], gt_deg[s])
        ep_total = ep_total + ew * torch.where(
            de < d2, de.pow(2)/(2*d2), de - d2/2).mean() / d2
        ep_w += ew
    l_ep  = ep_total / max(ep_w, 1e-6)
    l_sat = _signed_ate_loss(pred_deg, gt_deg)
    l_sct = _signed_cte_loss(pred_deg, gt_deg)
    l_dep = _direct_endpoint_loss(pred_deg, gt_deg, epoch)

    total = (0.60 * l_dpe + 0.02 * l_mse + 0.05 * l_speed
             + 0.08 * l_heading + 2.00 * l_vel + 0.30 * l_sbias
             + 0.25 * ate_d["ate_cte_total"] + 0.15 * l_ep
             + w_sat * l_sat + w_sct * l_sct + l_dep)

    if torch.isnan(total) or torch.isinf(total):
        total = pred_deg.new_zeros(())

    def _s(x): return x.item() if torch.is_tensor(x) else float(x)
    return dict(
        total        = total,
        dpe          = _s(l_dpe),
        mse          = _s(l_mse),
        vel_reg      = _s(l_vel),
        speed_bias   = _s(l_sbias),
        ate          = _s(ate_d["ate"]),
        cte          = _s(ate_d["cte"]),
        endpoint     = _s(l_ep),
        signed_ate   = _s(l_sat),
        signed_cte   = _s(l_sct),
        w_signed_ate = w_sat,
        ate_mean_km  = ate_d.get("ate_mean_km", 0.0),
        cte_mean_km  = ate_d.get("cte_mean_km", 0.0),
    )


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  Sinkhorn OT matching  (unchanged from v62)
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

def _sinkhorn_log(cost, epsilon=0.05, n_iter=50):
    B = cost.shape[0]; device = cost.device
    log_a = -math.log(B) * torch.ones(B, device=device)
    log_b = -math.log(B) * torch.ones(B, device=device)
    log_K = -cost / epsilon
    log_u = torch.zeros(B, device=device)
    log_v = torch.zeros(B, device=device)
    for _ in range(n_iter):
        log_u = log_a - torch.logsumexp(log_K + log_v.unsqueeze(0), dim=1)
        log_v = log_b - torch.logsumexp(log_K + log_u.unsqueeze(1), dim=0)
    return (log_K + log_u.unsqueeze(1) + log_v.unsqueeze(0)).exp().clamp(0.0)


def _geodesic_ot_cost(x0_rel, x1_rel, lp):
    B = x0_rel.shape[0]
    def _abs_deg(rel):
        return _norm_to_deg(lp.unsqueeze(1) + rel[:, :, :2])
    x0d = _abs_deg(x0_rel); x1d = _abs_deg(x1_rel)
    x0e = x0d.unsqueeze(1).expand(B, B, -1, -1).reshape(B*B, -1, 2)
    x1e = x1d.unsqueeze(0).expand(B, B, -1, -1).reshape(B*B, -1, 2)
    pos_cost   = _haversine_deg(x0e, x1e).reshape(B, B, -1).mean(-1) / 500.0
    spd0 = _step_speeds_deg(x0d.permute(1,0,2)).permute(1,0).mean(-1)
    spd1 = _step_speeds_deg(x1d.permute(1,0,2)).permute(1,0).mean(-1)
    speed_cost = (spd0.unsqueeze(1) - spd1.unsqueeze(0)).abs() / 20.0
    def _mean_bearing(td):
        b = _forward_azimuth(td[:,:-1,:], td[:,1:,:])
        return torch.atan2(b.sin().mean(-1), b.cos().mean(-1))
    h0 = _mean_bearing(x0d); h1 = _mean_bearing(x1d)
    dh = (h0.unsqueeze(1) - h1.unsqueeze(0) + math.pi) % (2*math.pi) - math.pi
    return 1.0*pos_cost + 0.5*speed_cost + 0.3*dh.abs()/math.pi


def _spherical_ot_matching(x0_batch, x1_batch, lp, epsilon=0.05):
    B = x0_batch.shape[0]
    if B < 4:
        return x0_batch, x1_batch
    try:
        cost = _geodesic_ot_cost(x0_batch, x1_batch, lp)
        with torch.no_grad():
            pi = _sinkhorn_log(cost, epsilon=epsilon)
        flat = pi.reshape(-1).clamp(0.0)
        s    = flat.sum()
        if not torch.isfinite(s) or s < 1e-10:
            return x0_batch, x1_batch
        idx = torch.multinomial(flat / s, num_samples=B, replacement=True)
        col = idx % B
        return x0_batch[col], x1_batch[col]
    except Exception:
        return x0_batch, x1_batch


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  Speed conditioning encoder  (unchanged from v62)
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

class SpeedConditioningEncoder(nn.Module):
    def __init__(self, out_dim: int = 256, speed_max: float = 80.0):
        super().__init__()
        self.speed_max = speed_max
        self.mlp = nn.Sequential(
            nn.Linear(64, 256), nn.GELU(), nn.LayerNorm(256),
            nn.Linear(256, out_dim), nn.GELU(),
        )
        self.scale = nn.Parameter(torch.ones(1) * 0.5)

    def _sinusoidal(self, x, dim=64):
        half = dim // 2
        freq = torch.exp(
            torch.arange(half, dtype=torch.float32, device=x.device)
            * (-math.log(1000.0) / max(half - 1, 1)))
        x_n = (x / self.speed_max).clamp(0.0, 1.5)
        emb  = x_n.unsqueeze(1) * freq.unsqueeze(0)
        return F.pad(torch.cat([emb.sin(), emb.cos()], dim=-1), (0, dim % 2))

    def forward(self, obs_speed_p50):
        return torch.sigmoid(self.scale) * self.mlp(
            self._sinusoidal(obs_speed_p50.float()))


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  SSFM Velocity Field  (replaces v62 VelocityField)
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

class SSFMVelocityField(nn.Module):
    """
    Updated velocity field for SSFM:
      - Adds IntensitySteeringExtractor [C1]
      - Replaces ARHead with NonARTransformerHead [C2]
      - Keeps all other components from v62 VelocityField
    """
    RAW_CTX_DIM = 512

    def __init__(self, pred_len=12, obs_len=8, ctx_dim=256,
                 sigma_min=0.02, unet_in_ch=13, **kwargs):
        super().__init__()
        self.pred_len = pred_len
        self.obs_len  = obs_len

        # ŌöĆŌöĆ Spatial encoder ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        self.spatial_enc     = FNO3DEncoder(
            in_channel=unet_in_ch, out_channel=1, d_model=32,
            n_layers=4, modes_t=4, modes_h=4, modes_w=4,
            spatial_down=32, dropout=0.05)
        self.bottleneck_proj = nn.Linear(128, 128)
        self.decoder_proj    = nn.Linear(128, 16)

        # ŌöĆŌöĆ Trajectory encoder ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        self.enc_1d  = DataEncoder1D(
            in_1d=4, feat_3d_dim=128, mlp_h=64,
            lstm_hidden=128, lstm_layers=3, dropout=0.15, d_state=16)
        self.env_enc = Env_net(obs_len=obs_len, d_model=32)

        # ŌöĆŌöĆ Context fusion ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        # h_t: Mamba(128) + FNO_global(128) = 256
        # e_env: 32, f_sp: 16 ŌåÆ total: 304
        self.ctx_fc1  = nn.Linear(256 + 32 + 16, self.RAW_CTX_DIM)
        self.ctx_ln   = nn.LayerNorm(self.RAW_CTX_DIM)
        self.ctx_drop = nn.Dropout(0.15)
        self.ctx_fc2  = nn.Linear(self.RAW_CTX_DIM, ctx_dim)
        self.null_embedding = nn.Parameter(torch.randn(1, self.RAW_CTX_DIM) * 0.02)

        # ŌöĆŌöĆ [C2] NAR head path: separate projection for ATE gradient ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        # Gradient: haversine(nar_pred, GT) ŌåÆ ctx_fc2_nar ŌåÆ raw_ctx ŌåÆ encoder
        # This path is 100% dedicated to ATE metric supervision
        self.ctx_fc2_nar = nn.Linear(self.RAW_CTX_DIM, ctx_dim)

        # ŌöĆŌöĆ Auxiliary feature encoders ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        self.vel_obs_enc = nn.Sequential(
            nn.Linear(obs_len * 6, 256), nn.GELU(), nn.LayerNorm(256),
            nn.Linear(256, 256), nn.GELU())
        self.steering_enc = nn.Sequential(
            nn.Linear(7, 64), nn.GELU(), nn.LayerNorm(64),
            nn.Linear(64, 128), nn.GELU(), nn.Linear(128, 256))
        self.env_kine_enc = nn.Sequential(
            nn.Linear(28, 128), nn.GELU(), nn.LayerNorm(128),
            nn.Linear(128, 256), nn.GELU())
        self.speed_cond_enc = SpeedConditioningEncoder(out_dim=256)

        # ŌöĆŌöĆ Speed regression head (auxiliary) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        self.speed_head = nn.Sequential(
            nn.Linear(256, 128), nn.GELU(), nn.LayerNorm(128),
            nn.Linear(128, pred_len))

        # ŌöĆŌöĆ [C1] Intensity-Dependent Steering Extractor ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        self.steering_extractor = IntensitySteeringExtractor(
            hidden_dim=128, n_levels=3)

        # ŌöĆŌöĆ [C2] Non-Autoregressive Transformer Head (replaces ARHead) ŌöĆŌöĆŌöĆŌöĆŌöĆ
        self.nar_head = NonARTransformerHead(
            ctx_dim=ctx_dim, pred_len=pred_len,
            n_heads=8, n_layers=3, dropout=0.10, expand_memory=4)

        # ŌöĆŌöĆ FM velocity field (Transformer decoder) ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        self.time_fc1   = nn.Linear(256, 512)
        self.time_fc2   = nn.Linear(512, 256)
        self.traj_embed = nn.Linear(4, 256)
        self.pos_enc    = nn.Parameter(torch.randn(1, pred_len, 256) * 0.02)
        self.step_embed = nn.Embedding(pred_len, 256)
        self.transformer = nn.TransformerDecoder(
            nn.TransformerDecoderLayer(
                d_model=256, nhead=8, dim_feedforward=1024,
                dropout=0.15, activation="gelu", batch_first=True),
            num_layers=4)
        self.out_fc1 = nn.Linear(256, 512)
        self.out_fc2 = nn.Linear(512, 4)

        self.step_scale     = nn.Parameter(torch.ones(pred_len) * 0.5)
        self.physics_scale  = nn.Parameter(torch.ones(4) * 1.5)
        self.steering_scale = nn.Parameter(torch.ones(4) * 1.0)
        self._init_weights()

    def _init_weights(self):
        with torch.no_grad():
            for name, m in self.named_modules():
                if isinstance(m, nn.Linear) and "out_fc" in name:
                    nn.init.xavier_uniform_(m.weight, gain=0.1)
                    if m.bias is not None: nn.init.zeros_(m.bias)

    def _time_emb(self, t, dim=256):
        half = dim // 2
        freq = torch.exp(torch.arange(half, dtype=torch.float32, device=t.device)
                         * (-math.log(10000.0) / max(half-1, 1)))
        emb  = t.float().unsqueeze(1) * 1000.0 * freq.unsqueeze(0)
        return F.pad(torch.cat([emb.sin(), emb.cos()], dim=-1), (0, dim % 2))

    def _context(self, batch_list):
        obs_traj  = batch_list[0]
        obs_Me    = batch_list[7]
        image_obs = batch_list[11]
        env_data  = batch_list[13]
        if image_obs.dim() == 4: image_obs = image_obs.unsqueeze(2)
        if image_obs.shape[1] == 1 and self.spatial_enc.in_channel != 1:
            image_obs = image_obs.expand(-1, self.spatial_enc.in_channel, -1, -1, -1)

        e_3d_bot, e_3d_dec = self.spatial_enc.encode(image_obs)
        T_obs = obs_traj.shape[0]
        e_3d_s = e_3d_bot.mean(dim=(-2, -1)).permute(0, 2, 1)
        e_3d_s = self.bottleneck_proj(e_3d_s)
        if e_3d_s.shape[1] != T_obs:
            e_3d_s = F.interpolate(e_3d_s.permute(0,2,1), size=T_obs,
                                   mode="linear", align_corners=False).permute(0,2,1)
        global_3d = e_3d_s.mean(dim=1)
        f_sp      = self.decoder_proj(global_3d)

        obs_in     = torch.cat([obs_traj, obs_Me], dim=2).permute(1,0,2)
        h_t_mamba  = self.enc_1d(obs_in, e_3d_s)
        h_t        = torch.cat([h_t_mamba, global_3d], dim=-1)

        e_env, _, _ = self.env_enc(env_data, image_obs)
        return F.gelu(self.ctx_ln(self.ctx_fc1(
            torch.cat([h_t, e_env, f_sp], dim=-1))))

    def _apply_ctx_head(self, raw, noise_scale=0.0, use_null=False):
        if use_null:
            raw = self.null_embedding.expand(raw.shape[0], -1)
        elif noise_scale > 0.0:
            raw = raw + torch.randn_like(raw) * noise_scale
        return self.ctx_fc2(self.ctx_drop(raw))

    def _get_kinematic_obs_feat(self, obs_traj):
        B, T_obs = obs_traj.shape[1], obs_traj.shape[0]
        if T_obs >= 2:
            vel     = obs_traj[1:] - obs_traj[:-1]
            lat_mid = obs_traj[:-1, :, 1] * _NORM_TO_DEG
            cos_lat = torch.cos(torch.deg2rad(lat_mid)).clamp(1e-4)
            dx_km   = vel[:,:,0] * cos_lat * DEG2KM * _NORM_TO_DEG
            dy_km   = vel[:,:,1]             * DEG2KM * _NORM_TO_DEG
            speed   = torch.sqrt(dx_km**2 + dy_km**2 + 1e-6) / DT_HOURS
            heading = torch.atan2(vel[:,:,1], vel[:,:,0])
            speed_n = (speed / 20.0).clamp(-3.0, 3.0)
            if T_obs >= 3:
                dspd  = speed[1:] - speed[:-1]
                accel = torch.cat([obs_traj.new_zeros(1,B),
                                   (dspd/10.0).clamp(-3.0,3.0)], 0)
            else:
                accel = obs_traj.new_zeros(T_obs-1, B)
            kine = torch.stack([vel[:,:,0], vel[:,:,1], speed_n,
                                 heading.sin(), heading.cos(), accel], dim=-1)
        else:
            kine = obs_traj.new_zeros(self.obs_len, B, 6)
        if kine.shape[0] < self.obs_len:
            kine = torch.cat([obs_traj.new_zeros(
                self.obs_len-kine.shape[0], B, 6), kine], 0)
        else:
            kine = kine[-self.obs_len:]
        return self.vel_obs_enc(kine.permute(1,0,2).reshape(B, -1))

    def _get_steering_feat(self, env_data, B, device):
        if env_data is None: return torch.zeros(B, 256, device=device)
        def _safe(k, norm=1.0):
            v = env_data.get(k)
            if v is None or not torch.is_tensor(v):
                return torch.full((B,), 0.0, device=device)
            v = v.float().to(device)
            while v.dim() > 1: v = v.mean(-1)
            v = v.view(-1)[:B] if v.numel() >= B else torch.full((B,), 0.0, device=device)
            return (v / norm).clamp(-3.0, 3.0)
        return self.steering_enc(torch.stack([
            _safe("u500_mean",      30.0), _safe("v500_mean",      30.0),
            _safe("u500_center",    30.0), _safe("v500_center",    30.0),
            _safe("steering_speed",  1.0), _safe("steering_dir_sin",1.0),
            _safe("steering_dir_cos",1.0),
        ], dim=-1))

    def _get_env_kine_feat(self, env_data, B, device):
        if env_data is None: return torch.zeros(B, 256, device=device)
        def _get_t(key, dim):
            v = env_data.get(key)
            if v is None: return torch.zeros(B, dim, device=device)
            if not torch.is_tensor(v):
                try: v = torch.tensor(v, dtype=torch.float, device=device)
                except: return torch.zeros(B, dim, device=device)
            v = v.float().to(device)
            if v.dim() == 0: return v.expand(B, 1) if dim==1 else torch.zeros(B, dim, device=device)
            if v.dim() == 1:
                if v.shape[0] == dim: return v.unsqueeze(0).expand(B, dim)
                if v.shape[0] == B: return v.unsqueeze(1).expand(B, dim) if dim==1 else torch.zeros(B, dim, device=device)
            if v.dim() == 2:
                if v.shape == (B, dim): return v
                return v[:B, :dim] if v.shape[1] >= dim else F.pad(v[:B], (0, dim-v.shape[1]))
            if v.dim() == 3:
                vv = v[:B, -1]
                return vv[:, :dim] if vv.shape[-1] >= dim else F.pad(vv, (0, dim-vv.shape[-1]))
            return torch.zeros(B, dim, device=device)

        def _ri_proxy(B, device):
            ic = _get_t("intensity_class", 6)
            return (ic * torch.arange(6, dtype=torch.float, device=device).unsqueeze(0) / 5.0
                    ).sum(-1, keepdim=True).clamp(0, 1)

        feat = torch.cat([
            (_get_t("move_velocity", 1) * (1219.84 / 150.0)).clamp(-3, 3),
            _get_t("history_direction12",  8),
            _get_t("history_direction24",  8),
            _get_t("delta_velocity",       5),
            _get_t("history_inte_change24",4),
            _get_t("gph500_center",        1),
            _ri_proxy(B, device),
        ], dim=-1)
        return self.env_kine_enc(feat)

    def _get_speed_cond_feat(self, obs_traj):
        with torch.no_grad():
            stats = compute_speed_stats_from_norm(obs_traj[..., :2])
            p50   = stats.get("p50_kmh", 15.0)
        B = obs_traj.shape[1]
        spd_t = torch.full((B,), p50, dtype=torch.float32, device=obs_traj.device)
        return self.speed_cond_enc(spd_t)

    def _get_intensity_onehot(self, env_data, B, device):
        """Extract one-hot intensity class from env_data for [C1]."""
        if env_data is None:
            return torch.zeros(B, 6, device=device)
        ic = env_data.get("intensity_class")
        if ic is None or not torch.is_tensor(ic):
            return torch.zeros(B, 6, device=device)
        ic = ic.float().to(device)
        if ic.dim() == 1:
            if ic.shape[0] == 6:
                return ic.unsqueeze(0).expand(B, -1)
            elif ic.shape[0] == B:
                return ic.unsqueeze(1).expand(B, 6)
            return torch.zeros(B, 6, device=device)
        if ic.dim() == 2:
            if ic.shape == (B, 6): return ic
            if ic.shape[1] == 6:   return ic[:B]
        return torch.zeros(B, 6, device=device)

    def _beta_drift(self, x_t):
        lat_rad = torch.deg2rad(x_t[:,:,1]*5.0).clamp(-85,85)
        beta    = 2*7.2921e-5*torch.cos(lat_rad)/6.371e6
        R_tc    = 3e5
        v = torch.zeros_like(x_t)
        v[:,:,0] = -beta*R_tc**2/2*6*3600/(5*111*1000)
        v[:,:,1] =  beta*R_tc**2/4*6*3600/(5*111*1000)
        return v

    def _steering_drift(self, x_t, env_data):
        if env_data is None: return torch.zeros_like(x_t)
        B, device = x_t.shape[0], x_t.device
        def _sm(k):
            v = env_data.get(k)
            if v is None or not torch.is_tensor(v):
                return torch.zeros(B, device=device)
            v = v.float().to(device)
            while v.dim() > 1: v = v.mean(-1)
            return v.view(-1)[:B] if v.numel() >= B else torch.zeros(B, device=device)
        u   = _sm("u500_center"); vv = _sm("v500_center")
        cos = torch.cos(torch.deg2rad(x_t[:,:,1]*5.0)).clamp(1e-3)
        out = torch.zeros_like(x_t)
        out[:,:,0] = u.unsqueeze(1)*30.0*21600.0/(111.0*1000.0*cos)
        out[:,:,1] = vv.unsqueeze(1)*30.0*21600.0/(111.0*1000.0)
        return out

    def _decode(self, x_t, t, ctx, vel_obs_feat=None, steering_feat=None,
                env_kine_feat=None, speed_cond_feat=None, env_data=None):
        B = x_t.shape[0]
        t_emb = F.gelu(self.time_fc1(self._time_emb(t)))
        t_emb = self.time_fc2(t_emb)
        T_seq    = min(x_t.size(1), self.pos_enc.shape[1])
        step_idx = torch.arange(T_seq, device=x_t.device).unsqueeze(0).expand(B,-1)
        x_emb = (self.traj_embed(x_t[:,:T_seq])
                 + self.pos_enc[:,:T_seq]
                 + t_emb.unsqueeze(1)
                 + self.step_embed(step_idx))
        mem = [t_emb.unsqueeze(1), ctx.unsqueeze(1)]
        if vel_obs_feat   is not None: mem.append(vel_obs_feat.unsqueeze(1))
        if steering_feat  is not None: mem.append(steering_feat.unsqueeze(1))
        if env_kine_feat  is not None: mem.append(env_kine_feat.unsqueeze(1))
        if speed_cond_feat is not None: mem.append(speed_cond_feat.unsqueeze(1))
        decoded  = self.transformer(x_emb, torch.cat(mem, dim=1))
        v_neural = self.out_fc2(F.gelu(self.out_fc1(decoded)))
        scale    = torch.sigmoid(self.step_scale[:T_seq]).view(1,T_seq,1) * 2.0
        v_neural = v_neural * scale
        with torch.no_grad():
            v_phys  = self._beta_drift(x_t[:,:T_seq])
            v_steer = self._steering_drift(x_t[:,:T_seq], env_data)
        return (v_neural
                + torch.sigmoid(self.physics_scale)*v_phys
                + torch.sigmoid(self.steering_scale)*v_steer)

    def forward_with_ctx(self, x_t, t, raw_ctx, noise_scale=0.0,
                         vel_obs_feat=None, steering_feat=None,
                         env_kine_feat=None, speed_cond_feat=None,
                         env_data=None, use_null=False):
        ctx = self._apply_ctx_head(raw_ctx, noise_scale, use_null=use_null)
        return self._decode(x_t, t, ctx,
                            vel_obs_feat=vel_obs_feat, steering_feat=steering_feat,
                            env_kine_feat=env_kine_feat, speed_cond_feat=speed_cond_feat,
                            env_data=env_data)


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  Inference helpers  (adapted from v62)
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

@torch.no_grad()
def _speed_sweep_correction(pred_traj_norm, obs_traj_norm,
                             scales=(0.65, 0.80, 0.90, 1.00, 1.10, 1.25, 1.45)):
    T_obs = obs_traj_norm.shape[0]; T = pred_traj_norm.shape[0]
    B, device = pred_traj_norm.shape[1], pred_traj_norm.device
    if T_obs < 2: return pred_traj_norm, torch.ones(B, device=device)
    obs_spd_all = _step_speeds_deg(_norm_to_deg(obs_traj_norm))
    n_obs = obs_spd_all.shape[0]
    if n_obs >= 3:
        alpha = 0.65
        w = torch.tensor([alpha*(1-alpha)**i for i in range(n_obs)],
                         dtype=torch.float, device=device).flip(0)
        obs_spd = (obs_spd_all * (w/w.sum()).unsqueeze(1)).sum(0)
    elif n_obs == 2:
        obs_spd = 0.65*obs_spd_all[-1] + 0.35*obs_spd_all[-2]
    else:
        obs_spd = obs_spd_all[-1]
    obs_spd   = obs_spd.clamp(min=2.0)
    anchor    = obs_traj_norm[-1].unsqueeze(0)
    disp      = pred_traj_norm - anchor
    t_idx     = torch.arange(T, dtype=torch.float, device=device)
    best_sc   = torch.full((B,), -1e9, device=device)
    best_traj = pred_traj_norm
    for s in scales:
        decay_exp = 1.0 - (t_idx / max(T-1, 1)) * 0.7
        scale_t   = torch.full((T,), s, device=device) ** decay_exp
        cand      = anchor + disp * scale_t.view(T,1,1)
        full_deg  = torch.cat([_norm_to_deg(anchor), _norm_to_deg(cand)], dim=0)
        cand_spd  = _step_speeds_deg(full_deg[:min(4,T)+1]).mean(0)
        score     = torch.exp(-((cand_spd - obs_spd)/obs_spd).pow(2)*4.0)
        better    = score > best_sc
        best_traj = torch.where(better.view(1,B,1).expand_as(cand), cand, best_traj)
        best_sc   = torch.where(better, score, best_sc)
    return best_traj, best_sc


def _score_ensemble_member(traj_norm, obs_traj_norm, speed_stats=None):
    sp      = speed_stats or _SPEED_PRIOR
    v_opt   = sp.get("v_opt", 15.0)
    v_sigma = sp.get("v_sigma", 10.0)
    v_cap   = sp.get("v_hard_cap", 35.0)
    B, device = traj_norm.shape[1], traj_norm.device
    spd = _step_speeds_deg(_norm_to_deg(traj_norm))
    dtd = _norm_to_deg(traj_norm[1:]) - _norm_to_deg(traj_norm[:-1])
    prior_sc  = torch.exp(-(((spd-v_opt)/v_sigma).pow(2) +
                             F.relu(spd-v_cap)*2.0).mean(0)*0.5)
    smooth_sc = (torch.exp(-(dtd[1:]-dtd[:-1]).norm(dim=-1).mean(0)*5.0)
                 if dtd.shape[0] >= 2 else torch.ones(B, device=device))
    if obs_traj_norm is not None and obs_traj_norm.shape[0] >= 2:
        obs_v   = obs_traj_norm[-1] - obs_traj_norm[-2]
        if obs_traj_norm.shape[0] >= 3:
            obs_v = 0.7*obs_v + 0.3*(obs_traj_norm[-2]-obs_traj_norm[-3])
        obs_hn  = F.normalize(obs_v, dim=-1, eps=1e-6)
        n_h     = min(3, traj_norm.shape[0]-1)
        pv_m    = (traj_norm[1:1+n_h]-traj_norm[:n_h]).mean(0) if n_h>=1 else obs_v
        pred_hn = F.normalize(pv_m, dim=-1, eps=1e-6)
        head_sc = torch.exp(((obs_hn*pred_hn).sum(-1)-1.0)*3.0)
        obs_ref = _step_speeds_deg(_norm_to_deg(obs_traj_norm))[
            -min(3, obs_traj_norm.shape[0]-1):].mean(0)
        spd_sc  = torch.exp(-((spd[:min(4,spd.shape[0])].mean(0) - obs_ref)
                               / obs_ref.clamp(min=5.0)).pow(2)*3.0)
    else:
        head_sc = spd_sc = torch.ones(B, device=device)
    return (head_sc.pow(0.35) * spd_sc.pow(0.30)
            * prior_sc.pow(0.20) * smooth_sc.pow(0.15))


# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
#  TCStochasticSFM ŌĆö Main Model  [C1 + C2 + C3]
# ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ

class TCStochasticSFM(nn.Module):
    """
    Stochastic Steering Flow Matching (SSFM) for TC track forecasting.

    Three novel contributions integrated into one framework:

    [C1] Physics source distribution:
         x0 = IntensitySteeringExtractor(ERA5, intensity_class) ├Ś dt + ╬▓_drift + Žā╬Ą
         FM only learns residual: u_target = GT ŌłÆ x0_physics
         Short transport ŌåÆ faster convergence ŌåÆ better ATE

    [C2] Non-AR Transformer head:
         ctx ŌåÆ NonARTransformerHead ŌåÆ T positions (all parallel)
         100% haversine gradient to encoder, no AR error accumulation
         Dedicated gradient path (ctx_fc2_nar) separate from FM path

    [C3] Energy Score + Calibration:
         mini-ensemble (N=4) generated at training time (physics x0 perturbs)
         Energy Score: proper scoring rule (Gneiting & Raftery 2007)
         Spread-Error calibration: log(spread) Ōēł log(error) per step
         ŌåÆ FM spread naturally encodes forecast difficulty
    """

    def __init__(
        self,
        pred_len: int = 12,
        obs_len:  int = 8,
        sigma_min: float = 0.02,
        sigma_physics: float = 0.25,   # [C1] noise around physics x0
        n_train_ens: int = 4,
        unet_in_ch:  int = 13,
        ctx_noise_scale: float = 0.01,
        initial_sample_sigma: float = 0.03,
        use_ema:   bool = True,
        ema_decay: float = 0.995,
        use_ate_ot: bool = True,
        ot_epsilon: float = 0.05,
        cfg_guidance_scale: float = 1.5,
        cfg_uncond_prob:    float = 0.10,
        # [C3] calibration weights
        w_energy_score:  float = 0.15,
        w_calibration:   float = 0.10,
        n_calibration_samples: int = 4,
        **kwargs,
    ):
        super().__init__()
        self.pred_len      = pred_len
        self.obs_len       = obs_len
        self.sigma_min     = sigma_min
        self.sigma_physics = sigma_physics   # [C1]
        self.ctx_noise_scale = ctx_noise_scale
        self.active_pred_len = pred_len
        self.use_ate_ot    = use_ate_ot
        self.ot_epsilon    = ot_epsilon
        self.cfg_guidance_scale = cfg_guidance_scale
        self.cfg_uncond_prob    = cfg_uncond_prob
        self.w_energy_score     = w_energy_score      # [C3]
        self.w_calibration      = w_calibration       # [C3]
        self.n_calibration_samples = n_calibration_samples  # [C3]
        self._current_epoch  = 0

        self.net     = SSFMVelocityField(
            pred_len=pred_len, obs_len=obs_len,
            sigma_min=sigma_min, unet_in_ch=unet_in_ch)
        self.use_ema  = use_ema
        self.ema_decay = ema_decay
        self._ema     = None

    def init_ema(self):
        if self.use_ema:
            self._ema = EMAModel(self, decay=self.ema_decay)

    def ema_update(self):
        if self._ema is not None: self._ema.update(self)

    def set_curriculum_len(self, *a, **kw): pass

    @staticmethod
    def _to_rel(traj, Me, lp, lm):
        return torch.cat([traj - lp.unsqueeze(0),
                          Me  - lm.unsqueeze(0)], dim=-1).permute(1, 0, 2)

    @staticmethod
    def _to_abs(rel, lp, lm):
        d = rel.permute(1, 0, 2)
        return lp.unsqueeze(0) + d[:,:,:2], lm.unsqueeze(0) + d[:,:,2:]

    @staticmethod
    def _sigma_schedule(epoch):
        if epoch < 2:   return 0.10
        if epoch < 10:  return 0.10 - (epoch-2)/8.0 * (0.10 - 0.04)
        if epoch < 20:  return max(0.04 - (epoch-10)/10.0 * 0.01, 0.03)
        return 0.03

    @staticmethod
    def _lon_flip_aug(bl, p=0.3):
        if torch.rand(1).item() > p: return bl
        bl = list(bl)
        for i in [0, 1, 2, 3]:
            if torch.is_tensor(bl[i]) and bl[i].shape[-1] >= 1:
                t = bl[i].clone(); t[..., 0] = -t[..., 0]; bl[i] = t
        return bl

    @staticmethod
    def _obs_noise_aug(bl, sigma=0.005):
        if torch.rand(1).item() > 0.5: return bl
        bl = list(bl)
        if torch.is_tensor(bl[0]):
            bl[0] = bl[0] + torch.randn_like(bl[0]) * sigma
        return bl

    @staticmethod
    def _speed_aug(bl, p=0.3, scale_range=(0.7, 1.4)):
        if torch.rand(1).item() > p: return bl
        scale = scale_range[0] + torch.rand(1).item() * (scale_range[1] - scale_range[0])
        bl = list(bl)
        if not torch.is_tensor(bl[1]) or not torch.is_tensor(bl[0]): return bl
        lp_2d = bl[0][-1, :, :2]
        pred  = bl[1]
        disp  = pred - lp_2d.unsqueeze(0)
        bl[1] = lp_2d.unsqueeze(0) + disp * scale
        if torch.is_tensor(bl[8]):
            lm = bl[7][-1]
            disp_me = bl[8] - lm.unsqueeze(0)
            bl[8]   = lm.unsqueeze(0) + disp_me * scale
        return bl

    # ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    #  [C1] Physics x0 computation
    # ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

    def _compute_physics_x0(
        self,
        obs_traj:    torch.Tensor,
        env_data:    Optional[dict],
        pred_len:    int,
        device,
        intensity_onehot: Optional[torch.Tensor] = None,
    ) -> torch.Tensor:
        """
        [C1] Generate physics-based source distribution for FM.

        Physics model:
          pos[t] = pos[t-1] + decay(t) ├Ś v_steer(intensity) + ╬▓_drift(lat)

        where:
          v_steer = IntensitySteeringExtractor(ERA5 winds, intensity_class)
          ╬▓_drift = planetary vorticity gradient correction (westward + poleward)
          decay   = exp(-t ├Ś 0.03)  (slight weakening of persistence)

        This trajectory represents our BEST PHYSICS GUESS of TC motion.
        FM will then learn to correct the residual: u = GT - physics_x0.
        Short residual ŌåÆ FM learns faster, produces more accurate trajectories.

        Returns:
            x0_phys_rel : (B, T, 4) in relative normalized coordinates
                          relative to lp (last observed position)
        """
        B  = obs_traj.shape[1]
        lp = obs_traj[-1, :, :2]  # (B, 2) last observed position (normalized)

        # Intensity-dependent steering velocity (per 6-hour step, normalized)
        v_steer, level_w = self.net.steering_extractor(
            env_data, B, device, intensity_onehot)  # v_steer: (B, 2)

        # Integrate forward from last observation
        positions = []
        curr = lp.clone()

        for t in range(pred_len):
            # ╬▓-drift: planetary vorticity gradient (always present)
            lat_deg = curr[:, 1] * _NORM_TO_DEG
            lat_rad = torch.deg2rad(lat_deg.clamp(-85, 85))
            beta    = 2 * 7.2921e-5 * torch.cos(lat_rad) / 6.371e6  # [1/m]
            R_tc    = 3e5   # m (typical TC Rossby radius)
            dt_s    = 6 * 3600  # 6-hour step
            norm_scale = _NORM_TO_DEG * DEG2KM * 1000  # m per normalized unit
            beta_lon = -beta * R_tc**2 / 2 * dt_s / norm_scale  # (B,) normalized
            beta_lat =  beta * R_tc**2 / 4 * dt_s / norm_scale
            beta_vec = torch.stack([beta_lon, beta_lat], dim=-1)   # (B, 2)

            # Steering intensity: slight decay over longer forecast times
            # Physical rationale: steering wind may shift as TC moves away
            decay = math.exp(-t * 0.03)

            curr = curr + decay * v_steer + beta_vec
            curr = curr.clamp(-3.5, 3.5)  # safety clamp
            positions.append(curr)

        x0_phys_abs = torch.stack(positions, dim=0)    # (T, B, 2) normalized abs
        x0_phys_rel_pos = x0_phys_abs - lp.unsqueeze(0)  # (T, B, 2) relative
        # Convert to (B, T, 4): relative pos + zero Me offset
        x0_rel = torch.cat(
            [x0_phys_rel_pos.permute(1, 0, 2),
             torch.zeros(B, pred_len, 2, device=device)], dim=-1)
        return x0_rel   # (B, T, 4)

    def _cfm_physics_seeded(
        self,
        x0_phys_rel: torch.Tensor,   # (B, T, 4) physics source (detached)
        x1_gt_rel:   torch.Tensor,   # (B, T, 4) GT target (OT-matched)
        sigma_physics: Optional[float] = None,
    ) -> Tuple[torch.Tensor, torch.Tensor, torch.Tensor, torch.Tensor]:
        """
        [C1] Physics-seeded flow matching interpolant.

        Replaces standard FM (x0 = N(0,Žā┬▓)) with physics-informed source:
          x0 = physics_x0 + Žā_phys ├Ś ╬Ą     (diverse around physics forecast)
          x_t = (1-t)├Śx0 + t├Śx1             (linear interpolant)
          u_target = x1 - x0                 (residual velocity field)

        Key insight: FM only needs to learn corrections to physics forecast.
        If physics forecast error Ōēł 50-80 km (v. persistence ~120 km),
        the transport distance is halved ŌåÆ FM converges faster.

        Žā_physics = 0.25 provides diversity without losing physics structure.
        """
        if sigma_physics is None:
            sigma_physics = self.sigma_physics
        B = x1_gt_rel.shape[0]; device = x1_gt_rel.device
        noise = torch.randn_like(x0_phys_rel) * sigma_physics
        x0    = x0_phys_rel + noise                    # diverse physics source
        t     = torch.rand(B, device=device)
        te    = t.view(B, 1, 1)
        x_t      = (1.0 - te) * x0 + te * x1_gt_rel   # interpolant
        u_target = x1_gt_rel - x0                       # target: residual FM velocity
        return x_t, t, u_target, x0

    def _compute_obs_momentum(self, obs_traj_norm):
        T_obs = obs_traj_norm.shape[0]
        if T_obs < 2: return torch.zeros(obs_traj_norm.shape[1], 2,
                                          device=obs_traj_norm.device)
        vels = obs_traj_norm[1:] - obs_traj_norm[:-1]
        n_v  = vels.shape[0]
        if n_v >= 3:
            alpha = 0.65
            w = torch.tensor([alpha*(1-alpha)**i for i in range(n_v)],
                              dtype=torch.float,
                              device=obs_traj_norm.device).flip(0)
            return (vels * (w/w.sum()).view(-1,1,1)).sum(0)
        elif n_v == 2:
            return 0.65*vels[-1] + 0.35*vels[-2]
        return vels[-1]

    # ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    #  Training loss
    # ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

    def get_loss(self, batch_list, epoch=0, **kwargs):
        return self.get_loss_breakdown(batch_list, epoch=epoch)["total"]

    def get_loss_breakdown(self, batch_list, epoch=0, **kwargs):
        batch_list = self._lon_flip_aug(batch_list)
        batch_list = self._obs_noise_aug(batch_list, sigma=0.005)
        batch_list = self._speed_aug(batch_list, p=0.3)
        self._current_epoch = epoch

        obs_t    = batch_list[0]
        env_data = batch_list[13] if len(batch_list) > 13 else None
        lp, lm   = obs_t[-1], batch_list[7][-1]
        B, device = obs_t.shape[1], obs_t.device

        speed_stats = compute_speed_stats_from_norm(obs_t[..., :2])
        raw_ctx     = self.net._context(batch_list)

        # Shared feature computation (amortised over all loss terms)
        speed_cond_feat = self.net._get_speed_cond_feat(obs_t[:, :, :2])
        vel_obs_feat    = self.net._get_kinematic_obs_feat(obs_t[:, :, :2])
        steering_feat   = self.net._get_steering_feat(env_data, B, device)
        env_kine_feat   = self.net._get_env_kine_feat(env_data, B, device)
        intensity_oh    = self.net._get_intensity_onehot(env_data, B, device)

        T_active = self.active_pred_len
        gt_trunc = batch_list[1][:T_active]
        Me_trunc = batch_list[8][:T_active]
        x1_rel   = self._to_rel(gt_trunc, Me_trunc, lp, lm)

        # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
        # [C2] NAR Head: parallel trajectory prediction
        #      Gradient path: l_nar ŌåÆ nar_head ŌåÆ ctx_fc2_nar ŌåÆ raw_ctx ŌåÆ encoder
        #      100% haversine gradient, no AR error accumulation
        # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
        ctx_nar     = F.gelu(self.net.ctx_fc2_nar(self.net.ctx_drop(raw_ctx)))
        nar_pred_abs = self.net.nar_head(ctx_nar, lp)   # (T, B, 2)

        T_nar_loss   = min(nar_pred_abs.shape[0], gt_trunc.shape[0])
        nar_pred_deg = _norm_to_deg(nar_pred_abs[:T_nar_loss])
        gt_deg_main  = _norm_to_deg(gt_trunc[:T_nar_loss])
        sw_nar       = nar_pred_deg.new_tensor(STEP_WEIGHTS[:T_nar_loss])
        sw_nar       = sw_nar / sw_nar.sum() * T_nar_loss
        dist_nar     = _haversine_deg(nar_pred_deg, gt_deg_main)       # (T, B)
        l_nar        = (dist_nar / 200.0 * sw_nar.unsqueeze(1)).mean()
        nar_ate_km   = float(dist_nar.mean().detach())

        # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
        # [C1] Physics source distribution: x0 = steering + ╬▓ + Žā╬Ą
        #      FM learns residual: u_target = GT - physics_x0
        # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
        x0_phys = self._compute_physics_x0(
            obs_t, env_data, T_active, device, intensity_oh)  # (B, T, 4)

        # OT matching between physics x0 and GT (shorter transport ŌåÆ better OT)
        if self.use_ate_ot and B >= 4:
            _, x1_matched = _spherical_ot_matching(
                x0_phys.detach(), x1_rel, lp, epsilon=self.ot_epsilon)
        else:
            x1_matched = x1_rel

        x_t, fm_t, u_target, x0_sampled = self._cfm_physics_seeded(
            x0_phys.detach(),  # DETACH: FM grad does NOT go to steering_extractor
            x1_matched,        # GT (OT-matched)
        )

        use_null = (torch.rand(1).item() < self.cfg_uncond_prob)
        pred_vel = self.net.forward_with_ctx(
            x_t, fm_t, raw_ctx, env_data=env_data, use_null=use_null,
            vel_obs_feat=vel_obs_feat, steering_feat=steering_feat,
            env_kine_feat=env_kine_feat, speed_cond_feat=speed_cond_feat)

        l_fm_mse = F.mse_loss(pred_vel, u_target)

        fm_te    = fm_t.view(B, 1, 1)
        x1_pred  = x_t + (1.0 - fm_te) * pred_vel
        pred_abs, _ = self._to_abs(x1_pred, lp, lm)
        pred_deg    = _norm_to_deg(pred_abs)
        gt_deg      = _norm_to_deg(gt_trunc)

        loss_dict = compute_ssfm_loss(
            pred_deg, gt_deg, epoch=epoch, speed_stats=speed_stats)

        # Speed head supervision
        ctx_for_speed = self.net._apply_ctx_head(raw_ctx, noise_scale=0.0)
        pred_speed_h  = self.net.speed_head(ctx_for_speed)   # (B, 12)
        with torch.no_grad():
            gt_spd_steps = _step_speeds_deg(gt_deg[:T_active])
            if gt_spd_steps.shape[0] < 12:
                gt_spd_steps = torch.cat([
                    gt_spd_steps,
                    torch.zeros(12-gt_spd_steps.shape[0], B, device=device)], 0)
            gt_spd_n = (gt_spd_steps[:12].permute(1,0) / 20.0).clamp(0, 4)
        l_speed_head = F.mse_loss(pred_speed_h, gt_spd_n.detach()) * 3.0

        # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
        # [C3] Calibration: Energy Score + Spread-Error Loss
        #      Mini-ensemble: N samples from physics x0 perturbations
        #      No N extra FM forward passes: use different t values + x0 noise
        # ŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉŌĢÉ
        l_es  = x_t.new_zeros(())
        l_cal = x_t.new_zeros(())

        # Only compute calibration after epoch 5 (when FM has converged somewhat)
        # and every 2 steps (for efficiency; detach from main graph)
        N_cal = self.n_calibration_samples
        if epoch >= 5 and N_cal > 0:
            try:
                cal_preds = []  # List of (T, B, 2) degree predictions
                with torch.no_grad():
                    for _ in range(N_cal):
                        # Different noise sample from physics x0
                        t_cal   = torch.rand(B, device=device)
                        noise_c = torch.randn_like(x0_phys) * self.sigma_physics
                        x0_cal  = x0_phys + noise_c
                        te_cal  = t_cal.view(B, 1, 1)
                        x_t_cal = (1-te_cal)*x0_cal + te_cal*x1_matched
                        v_cal   = self.net.forward_with_ctx(
                            x_t_cal, t_cal, raw_ctx,
                            vel_obs_feat=vel_obs_feat,
                            steering_feat=steering_feat,
                            env_kine_feat=env_kine_feat,
                            speed_cond_feat=speed_cond_feat,
                            env_data=env_data)
                        x1_c    = x_t_cal + (1-te_cal)*v_cal
                        abs_c, _ = self._to_abs(x1_c, lp, lm)
                        cal_preds.append(_norm_to_deg(abs_c))  # (T, B, 2)

                # Stack to (N, T, B, 2)
                ens_deg = torch.stack(cal_preds, dim=0)        # (N, T, B, 2)
                T_cal   = min(ens_deg.shape[1], gt_deg.shape[0])
                gt_deg_cal = gt_deg[:T_cal]

                l_es  = _energy_score_loss(
                    ens_deg[:, :T_cal], gt_deg_cal)
                l_cal = _spread_error_calibration_loss(
                    ens_deg[:, :T_cal], gt_deg_cal)
            except Exception:
                pass  # Calibration loss is auxiliary; don't crash training

        # ŌöĆŌöĆ FM progressive weight ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        w_fm = min(8.0, 4.0 + max(0, epoch - 15) * 0.1)
        w_nar = 10.0  # [C2] Primary ATE gradient signal

        total = (w_fm * l_fm_mse
                 + 2.0 * loss_dict["total"]
                 + l_speed_head
                 + w_nar * l_nar                       # [C2]
                 + self.w_energy_score * l_es           # [C3]
                 + self.w_calibration  * l_cal)         # [C3]

        if torch.isnan(total) or torch.isinf(total):
            total = x_t.new_zeros(())

        d = dict(loss_dict)
        d.update({
            "total"       : total,
            "fm_mse"      : l_fm_mse.item(),
            "w_fm"        : w_fm,
            "nar_ate"     : nar_ate_km,         # [C2] MONITOR
            "w_nar"       : w_nar,
            "speed_head"  : l_speed_head.item() / 3.0,
            "energy_score": l_es.item() if torch.is_tensor(l_es) else float(l_es),
            "calibration" : l_cal.item() if torch.is_tensor(l_cal) else float(l_cal),
            "sigma"       : self._sigma_schedule(epoch),
            "v_opt"       : speed_stats.get("v_opt", 15.0),
            "obs_spd_p50" : speed_stats.get("p50_kmh", 0.0),
        })
        return d

    # ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
    #  Inference
    # ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ

    @torch.no_grad()
    def sample(
        self,
        batch_list,
        num_ensemble: int = 50,
        ddim_steps:   int = 20,
        predict_csv:  Optional[str] = None,
        importance_weight: bool = True,
        use_cfg:      bool = True,
    ):
        obs_t    = batch_list[0]
        env_data = batch_list[13] if len(batch_list) > 13 else None
        lp       = obs_t[-1]; lm = batch_list[7][-1]
        B        = lp.shape[0]; device = lp.device
        T        = self.pred_len; dt = 1.0 / max(ddim_steps, 1)

        raw_ctx        = self.net._context(batch_list)
        vel_obs_feat   = self.net._get_kinematic_obs_feat(obs_t[:, :, :2])
        steering_feat  = self.net._get_steering_feat(env_data, B, device)
        env_kine_feat  = self.net._get_env_kine_feat(env_data, B, device)
        speed_cond_feat= self.net._get_speed_cond_feat(obs_t[:, :, :2])
        speed_stats    = compute_speed_stats_from_norm(obs_t[..., :2])
        intensity_oh   = self.net._get_intensity_onehot(env_data, B, device)

        # [C1] Physics x0 as init distribution (replaces persistence init)
        x0_phys = self._compute_physics_x0(
            obs_t, env_data, T, device, intensity_oh)  # (B, T, 4)

        obs_norm = obs_t[:, :, :2]
        if obs_t.shape[0] >= 2:
            obs_h_n = F.normalize(
                obs_t[-1,:,:2] - obs_t[-2,:,:2], dim=-1, eps=1e-6)
        else:
            obs_h_n = None

        obs_mom = self._compute_obs_momentum(obs_norm)
        if obs_t.shape[0] >= 3:
            vv    = obs_t[1:,:,:2] - obs_t[:-1,:,:2]
            heads = F.normalize(vv, dim=-1, eps=1e-6)
            cos_s = (heads[1:]*heads[:-1]).sum(-1).mean(0)
            mom_gate = torch.sigmoid((cos_s-0.5)*8.0)
        else:
            mom_gate = torch.ones(B, device=device)

        def _mom_str(s, tot):
            return 0.08 * 0.5 * (1.0 + math.cos(math.pi*s/max(tot,1)))

        all_norms, all_me = [], []

        for ens_i in range(num_ensemble):
            # [C1] Init from physics x0 + diversity noise (not pure random noise)
            x_t = x0_phys + torch.randn_like(x0_phys) * self.sigma_physics

            for step in range(ddim_steps):
                t_b = torch.full((B,), step*dt, device=device)
                ns  = self.ctx_noise_scale * 2.0 if step < 3 else 0.0

                if use_cfg and step > 0:
                    v_cond   = self.net.forward_with_ctx(
                        x_t, t_b, raw_ctx, noise_scale=ns,
                        vel_obs_feat=vel_obs_feat, steering_feat=steering_feat,
                        env_kine_feat=env_kine_feat, speed_cond_feat=speed_cond_feat,
                        env_data=env_data, use_null=False)
                    v_uncond = self.net.forward_with_ctx(
                        x_t, t_b, raw_ctx, noise_scale=0.0,
                        vel_obs_feat=vel_obs_feat, steering_feat=steering_feat,
                        env_kine_feat=env_kine_feat, speed_cond_feat=speed_cond_feat,
                        env_data=env_data, use_null=True)
                    if obs_h_n is not None:
                        pred_h = F.normalize(v_cond[:,0,:2].detach(), dim=-1, eps=1e-6)
                        cos_a  = (obs_h_n * pred_h).sum(-1).clamp(-1.0, 1.0)
                        gs     = (0.8 + 0.7*(cos_a+1.0)*0.5).view(B,1,1)
                        vel    = v_uncond + gs * (v_cond - v_uncond)
                    else:
                        vel = v_uncond + 1.5 * (v_cond - v_uncond)
                else:
                    vel = self.net.forward_with_ctx(
                        x_t, t_b, raw_ctx, noise_scale=ns,
                        vel_obs_feat=vel_obs_feat, steering_feat=steering_feat,
                        env_kine_feat=env_kine_feat, speed_cond_feat=speed_cond_feat,
                        env_data=env_data)

                m_s = _mom_str(step, ddim_steps)
                if m_s > 1e-4:
                    me  = obs_mom.unsqueeze(1).expand(B, T, 2)
                    mf  = torch.cat([me, torch.zeros(B, T, 2, device=device)], -1)
                    vel = vel + m_s * mom_gate.view(B,1,1) * mf

                x_t = (x_t + dt*vel).clamp(-3.0, 3.0)

            tr, me = self._to_abs(x_t, lp, lm)
            all_norms.append(tr)
            all_me.append(me)

        SCALES = (0.65, 0.80, 0.90, 1.00, 1.10, 1.25, 1.45)
        cands, scores = [], []
        for tn in all_norms:
            bt, bsc = _speed_sweep_correction(tn, obs_norm, SCALES)
            cands.append(bt); scores.append(bsc)
            cands.append(tn)
            scores.append(_score_ensemble_member(tn, obs_norm, speed_stats))

        all_c  = torch.stack(cands)
        all_sc = torch.stack(scores)
        all_me_t = torch.stack(all_me)

        # ŌöĆŌöĆ [C2] NAR-Anchored Sample Selection ŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆŌöĆ
        # Use NAR head (clean ATE-supervised) as anchor for FM ensemble
        # Select the FM sample CLOSEST to NAR prediction
        ctx_nar     = F.gelu(self.net.ctx_fc2_nar(self.net.ctx_drop(raw_ctx)))
        anchor_abs  = self.net.nar_head(ctx_nar, lp)           # (T, B, 2)

        c_deg   = _norm_to_deg(all_c)                          # (N, T, B, 2)
        anc_deg = _norm_to_deg(anchor_abs)                     # (T, B, 2)
        diff    = c_deg - anc_deg.unsqueeze(0)
        # Weighted distance to anchor
        sw      = torch.tensor(STEP_WEIGHTS[:T], device=device, dtype=torch.float)
        sw      = sw / sw.sum()
        # Use approximate distance (faster than haversine for selection)
        cos_lat = torch.cos(torch.deg2rad(anc_deg[:,:,1])).clamp(1e-4)
        dist_km = torch.sqrt(
            (diff[:,:,:,0] * cos_lat.unsqueeze(0) * DEG2KM * _NORM_TO_DEG).pow(2) +
            (diff[:,:,:,1]                          * DEG2KM * _NORM_TO_DEG).pow(2) + 1e-6
        )                                                       # (N, T, B)
        ate_to_anchor  = (dist_km * sw.view(1, T, 1)).sum(1)   # (N, B)
        ate_norm  = ate_to_anchor / (ate_to_anchor.max(0).values.unsqueeze(0) + 1e-6)
        spd_norm  = all_sc / (all_sc.max(0).values.unsqueeze(0) + 1e-6)
        sel_score = (1.0 - ate_norm) * 0.65 + spd_norm * 0.35
        best_idx  = sel_score.argmax(0)
        pred_mean = torch.stack(
            [all_c[best_idx[b], :, b, :] for b in range(B)], dim=1)

        # Blend with NAR anchor (improves ATE systematically)
        _ep       = getattr(self, '_current_epoch', 0)
        anchor_w  = 0.15 if _ep < 20 else (0.20 if _ep < 40 else 0.25)
        pred_mean = (1.0 - anchor_w) * pred_mean + anchor_w * anchor_abs

        if predict_csv:
            self._write_predict_csv(predict_csv, pred_mean, all_c)
        return pred_mean, all_me_t.mean(0), all_c

    @staticmethod
    def _write_predict_csv(csv_path, traj_mean, all_trajs):
        os.makedirs(os.path.dirname(os.path.abspath(csv_path)), exist_ok=True)
        T, B, _ = traj_mean.shape
        mlon = ((traj_mean[...,0]*50.0+1800.0)/10.0).cpu().numpy()
        mlat = ((traj_mean[...,1]*50.0)/10.0).cpu().numpy()
        alon = ((all_trajs[...,0]*50.0+1800.0)/10.0).cpu().numpy()
        alat = ((all_trajs[...,1]*50.0)/10.0).cpu().numpy()
        fields = ["timestamp","batch_idx","step_idx","lead_h",
                  "lon_mean_deg","lat_mean_deg",
                  "lon_std_deg","lat_std_deg","ens_spread_km"]
        ts = datetime.now().strftime("%Y%m%d_%H%M%S")
        write_hdr = not os.path.exists(csv_path)
        with open(csv_path, "a", newline="") as fh:
            w = csv.DictWriter(fh, fieldnames=fields)
            if write_hdr: w.writeheader()
            for b in range(B):
                for k in range(T):
                    dlat   = alat[:,k,b] - mlat[k,b]
                    dlon   = ((alon[:,k,b] - mlon[k,b]) *
                              math.cos(math.radians(float(mlat[k,b]))))
                    spread = float(((dlat**2+dlon**2)**0.5).mean() * DEG2KM)
                    w.writerow({
                        "timestamp"    : ts,
                        "batch_idx"    : b,
                        "step_idx"     : k,
                        "lead_h"       : (k+1)*6,
                        "lon_mean_deg" : f"{mlon[k,b]:.4f}",
                        "lat_mean_deg" : f"{mlat[k,b]:.4f}",
                        "lon_std_deg"  : f"{alon[:,k,b].std():.4f}",
                        "lat_std_deg"  : f"{alat[:,k,b].std():.4f}",
                        "ens_spread_km": f"{spread:.2f}",
                    })


# Backward compat alias
TCFlowMatching = TCStochasticSFM